// generated from musescript/indicators/lib/BeltHold.hx\n@strategy(\"ta.belt_hold\")\n@on(bar) {\n  var v = belt_hold(0.5);\n  plot(v, \"belt_hold\");\n}\n", doc : "Belt Hold candlestick pattern — a single-bar reversal signal defined by a long body opening at one extreme of the bar...", file : "BeltHold.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "beta", sig : "beta(Series, Series, Window) -> Scalar", source : "// beta — Rolling Beta: the asset's sensitivity to the benchmark over a trailing window of `period` `(asset_return, benchmark_r...\n// sig: beta(Series, Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Beta.hx\n@strategy(\"ta.beta\")\n@on(bar) {\n  var v = beta(close, close, 5);\n  plot(v, \"beta\");\n}\n", doc : "Rolling Beta: the asset's sensitivity to the benchmark over a trailing window of `period` `(asset_return, benchmark_r...", file : "Beta.hx", argKinds : ["TSeries","TSeries","TWindow"], nativeSource : null},{ name : "beta_neutral_spread", sig : "beta_neutral_spread(Series, Series, Window) -> Scalar", source : "// beta_neutral_spread — Beta-neutral spread: the asset's return with its rolling-beta exposure to the benchmark hedged out\n// sig: beta_neutral_spread(Series, Series, Window) -> Scalar\n// generated from musescript/indicators/lib/BetaNeutralSpread.hx\n@strategy(\"ta.beta_neutral_spread\")\n@on(bar) {\n  var v = beta_neutral_spread(close, close, 5);\n  plot(v, \"beta_neutral_spread\");\n}\n", doc : "Beta-neutral spread: the asset's return with its rolling-beta exposure to the benchmark hedged out", file : "BetaNeutralSpread.hx", argKinds : ["TSeries","TSeries","TWindow"], nativeSource : null},{ name : "better_volume", sig : "better_volume(Window) -> Scalar", source : "// better_volume — Better Volume: the current bar's volume relative to its own trailing simple-moving-average volume\n// sig: better_volume(Window) -> Scalar\n// generated from musescript/indicators/lib/BetterVolume.hx\n@strategy(\"ta.better_volume\")\n@on(bar) {\n  var v = better_volume(5);\n  plot(v, \"better_volume\");\n}\n", doc : "Better Volume: the current bar's volume relative to its own trailing simple-moving-average volume", file : "BetterVolume.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "bipower_variation", sig : "bipower_variation(Series, Window) -> Scalar", source : "// bipower_variation — Realized Bipower Variation (Barndorff-Nielsen & Shephard) — a jump-robust estimator of realized variance over a rolli...\n// sig: bipower_variation(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/BipowerVariation.hx\n@strategy(\"ta.bipower_variation\")\n@on(bar) {\n  var v = bipower_variation(close, 5);\n  plot(v, \"bipower_variation\");\n}\n", doc : "Realized Bipower Variation (Barndorff-Nielsen & Shephard) — a jump-robust estimator of realized variance over a rolli...", file : "BipowerVariation.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "body_size_pct", sig : "body_size_pct() -> Scalar", source : "// body_size_pct — Candle body size as a percentage of the bar's total range: BodySizePct = |close - open| / (high - low) * 100 A statel...\n// sig: body_size_pct() -> Scalar\n// generated from musescript/indicators/lib/BodySizePct.hx\n@strategy(\"ta.body_size_pct\")\n@on(bar) {\n  var v = body_size_pct();\n  plot(v, \"body_size_pct\");\n}\n", doc : "Candle body size as a percentage of the bar's total range: BodySizePct = |close - open| / (high - low) * 100 A statel...", file : "BodySizePct.hx", argKinds : [], nativeSource : null},{ name : "bollinger", sig : "bollinger(Series, Window, Scalar) -> {upper, middle, lower}", source : "// bollinger — Bollinger Bands: an SMA centerline with bands `numStdDev` sample standard deviations away, both computed over the sam...\n// sig: bollinger(Series, Window, Scalar) -> {upper, middle, lower}\n// generated from musescript/indicators/lib/Bollinger.hx\n@strategy(\"ta.bollinger\")\n@on(bar) {\n  var v = bollinger(close, 5, 0.5);\n  plot(v.upper, \"bollinger.upper\");\n  plot(v.middle, \"bollinger.middle\");\n  plot(v.lower, \"bollinger.lower\");\n}\n", doc : "Bollinger Bands: an SMA centerline with bands `numStdDev` sample standard deviations away, both computed over the sam...", file : "Bollinger.hx", argKinds : ["TSeries","TWindow","TScalar"], nativeSource : null},{ name : "bollinger_bandwidth", sig : "bollinger_bandwidth(Series, Window, Scalar) -> Scalar", source : "// bollinger_bandwidth — Bollinger Bandwidth: the width of the Bollinger Bands normalized by the middle band, a standard measure of relative v...\n// sig: bollinger_bandwidth(Series, Window, Scalar) -> Scalar\n// generated from musescript/indicators/lib/BollingerBandwidth.hx\n@strategy(\"ta.bollinger_bandwidth\")\n@on(bar) {\n  var v = bollinger_bandwidth(close, 5, 0.5);\n  plot(v, \"bollinger_bandwidth\");\n}\n", doc : "Bollinger Bandwidth: the width of the Bollinger Bands normalized by the middle band, a standard measure of relative v...", file : "BollingerBandwidth.hx", argKinds : ["TSeries","TWindow","TScalar"], nativeSource : null},{ name : "bomar_bands", sig : "bomar_bands(Series, Window, Scalar) -> {upper, middle, lower}", source : "// bomar_bands — Bomar Bands\n// sig: bomar_bands(Series, Window, Scalar) -> {upper, middle, lower}\n// generated from musescript/indicators/lib/BomarBands.hx\n@strategy(\"ta.bomar_bands\")\n@on(bar) {\n  var v = bomar_bands(close, 5, 0.5);\n  plot(v.upper, \"bomar_bands.upper\");\n  plot(v.middle, \"bomar_bands.middle\");\n  plot(v.lower, \"bomar_bands.lower\");\n}\n", doc : "Bomar Bands", file : "BomarBands.hx", argKinds : ["TSeries","TWindow","TScalar"], nativeSource : null},{ name : "breakaway", sig : "breakaway(Window) -> Scalar", source : "// breakaway — Breakaway — a 5-bar reversal pattern\n// sig: breakaway(Window) -> Scalar\n// generated from musescript/indicators/lib/Breakaway.hx\n@strategy(\"ta.breakaway\")\n@on(bar) {\n  var v = breakaway(5);\n  plot(v, \"breakaway\");\n}\n", doc : "Breakaway — a 5-bar reversal pattern", file : "Breakaway.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "burke_ratio", sig : "burke_ratio(Series, Window) -> Scalar", source : "// burke_ratio — Burke Ratio: a drawdown-aware risk-adjusted return metric over a trailing window of `period` equity-curve samples\n// sig: burke_ratio(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/BurkeRatio.hx\n@strategy(\"ta.burke_ratio\")\n@on(bar) {\n  var v = burke_ratio(close, 5);\n  plot(v, \"burke_ratio\");\n}\n", doc : "Burke Ratio: a drawdown-aware risk-adjusted return metric over a trailing window of `period` equity-curve samples", file : "BurkeRatio.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "butterfly", sig : "butterfly() -> Scalar", source : "// butterfly — Butterfly harmonic pattern detector\n// sig: butterfly() -> Scalar\n// generated from musescript/indicators/lib/Butterfly.hx\n@strategy(\"ta.butterfly\")\n@on(bar) {\n  var v = butterfly();\n  plot(v, \"butterfly\");\n}\n", doc : "Butterfly harmonic pattern detector", file : "Butterfly.hx", argKinds : [], nativeSource : null},{ name : "calmar_ratio", sig : "calmar_ratio(Series, Window) -> Scalar", source : "// calmar_ratio — Calmar Ratio: mean return over the trailing window divided by the single worst peak-to-trough drawdown observed in th...\n// sig: calmar_ratio(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/CalmarRatio.hx\n@strategy(\"ta.calmar_ratio\")\n@on(bar) {\n  var v = calmar_ratio(close, 5);\n  plot(v, \"calmar_ratio\");\n}\n", doc : "Calmar Ratio: mean return over the trailing window divided by the single worst peak-to-trough drawdown observed in th...", file : "CalmarRatio.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "camarilla_pivots", sig : "camarilla_pivots() -> {r4, r3, r2, r1, pivot, s1, s2, s3, s4}", source : "// camarilla_pivots — Camarilla Pivots: intraday support/resistance levels derived from the *previous completed* bar's high/low/close, usin...\n// sig: camarilla_pivots() -> {r4, r3, r2, r1, pivot, s1, s2, s3, s4}\n// generated from musescript/indicators/lib/CamarillaPivots.hx\n@strategy(\"ta.camarilla_pivots\")\n@on(bar) {\n  var v = camarilla_pivots();\n  plot(v.r4, \"camarilla_pivots.r4\");\n  plot(v.r3, \"camarilla_pivots.r3\");\n  plot(v.r2, \"camarilla_pivots.r2\");\n  plot(v.r1, \"camarilla_pivots.r1\");\n  plot(v.pivot, \"camarilla_pivots.pivot\");\n  plot(v.s1, \"camarilla_pivots.s1\");\n  plot(v.s2, \"camarilla_pivots.s2\");\n  plot(v.s3, \"camarilla_pivots.s3\");\n  plot(v.s4, \"camarilla_pivots.s4\");\n}\n", doc : "Camarilla Pivots: intraday support/resistance levels derived from the *previous completed* bar's high/low/close, usin...", file : "CamarillaPivots.hx", argKinds : [], nativeSource : null},{ name : "candle_volume", sig : "candle_volume() -> Scalar", source : "// candle_volume — Candle Volume: a stateless pass-through of the bar's volume field, exposed as its own indicator so volume can be comp...\n// sig: candle_volume() -> Scalar\n// generated from musescript/indicators/lib/CandleVolume.hx\n@strategy(\"ta.candle_volume\")\n@on(bar) {\n  var v = candle_volume();\n  plot(v, \"candle_volume\");\n}\n", doc : "Candle Volume: a stateless pass-through of the bar's volume field, exposed as its own indicator so volume can be comp...", file : "CandleVolume.hx", argKinds : [], nativeSource : null},{ name : "cci", sig : "cci(Window, Scalar) -> Scalar", source : "// cci — Commodity Channel Index\n// sig: cci(Window, Scalar) -> Scalar\n// generated from musescript/indicators/lib/Cci.hx\n@strategy(\"ta.cci\")\n@on(bar) {\n  var v = cci(5, 0.5);\n  plot(v, \"cci\");\n}\n", doc : "Commodity Channel Index", file : "Cci.hx", argKinds : ["TWindow","TScalar"], nativeSource : null},{ name : "center_of_gravity", sig : "center_of_gravity(Series, Window) -> Scalar", source : "// center_of_gravity — Ehlers' Center of Gravity oscillator: a zero-lag, turning-point-focused oscillator over a trailing window of `period`...\n// sig: center_of_gravity(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/CenterOfGravity.hx\n@strategy(\"ta.center_of_gravity\")\n@on(bar) {\n  var v = center_of_gravity(close, 5);\n  plot(v, \"center_of_gravity\");\n}\n", doc : "Ehlers' Center of Gravity oscillator: a zero-lag, turning-point-focused oscillator over a trailing window of `period`...", file : "CenterOfGravity.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "central_pivot_range", sig : "central_pivot_range() -> {top, pivot, bottom}", source : "// central_pivot_range — Central Pivot Range (CPR): a three-line variant of the classic pivot that frames the pivot in a symmetric band, deriv...\n// sig: central_pivot_range() -> {top, pivot, bottom}\n// generated from musescript/indicators/lib/CentralPivotRange.hx\n@strategy(\"ta.central_pivot_range\")\n@on(bar) {\n  var v = central_pivot_range();\n  plot(v.top, \"central_pivot_range.top\");\n  plot(v.pivot, \"central_pivot_range.pivot\");\n  plot(v.bottom, \"central_pivot_range.bottom\");\n}\n", doc : "Central Pivot Range (CPR): a three-line variant of the classic pivot that frames the pivot in a symmetric band, deriv...", file : "CentralPivotRange.hx", argKinds : [], nativeSource : null},{ name : "cfo", sig : "cfo(Series, Window) -> Scalar", source : "// cfo — Chande Forecast Oscillator: how far the current price sits from the endpoint of a linear-regression line fit over the...\n// sig: cfo(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Cfo.hx\n@strategy(\"ta.cfo\")\n@on(bar) {\n  var v = cfo(close, 5);\n  plot(v, \"cfo\");\n}\n", doc : "Chande Forecast Oscillator: how far the current price sits from the endpoint of a linear-regression line fit over the...", file : "Cfo.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "chaikin_oscillator", sig : "chaikin_oscillator(Window, Window) -> Scalar", source : "// chaikin_oscillator — Chaikin Oscillator: the MACD-style spread between a fast and slow EMA of the Accumulation/Distribution Line (see `Adl`)\n// sig: chaikin_oscillator(Window, Window) -> Scalar\n// generated from musescript/indicators/lib/ChaikinOscillator.hx\n@strategy(\"ta.chaikin_oscillator\")\n@on(bar) {\n  var v = chaikin_oscillator(5, 10);\n  plot(v, \"chaikin_oscillator\");\n}\n", doc : "Chaikin Oscillator: the MACD-style spread between a fast and slow EMA of the Accumulation/Distribution Line (see `Adl`)", file : "ChaikinOscillator.hx", argKinds : ["TWindow","TWindow"], nativeSource : null},{ name : "chaikin_volatility", sig : "chaikin_volatility(Window, Window) -> Scalar", source : "// chaikin_volatility — Chaikin Volatility: the rate of change, over `rocPeriod` bars, of an EMA of the bar's high-low range\n// sig: chaikin_volatility(Window, Window) -> Scalar\n// generated from musescript/indicators/lib/ChaikinVolatility.hx\n@strategy(\"ta.chaikin_volatility\")\n@on(bar) {\n  var v = chaikin_volatility(5, 10);\n  plot(v, \"chaikin_volatility\");\n}\n", doc : "Chaikin Volatility: the rate of change, over `rocPeriod` bars, of an EMA of the bar's high-low range", file : "ChaikinVolatility.hx", argKinds : ["TWindow","TWindow"], nativeSource : null},{ name : "chande_kroll_stop", sig : "chande_kroll_stop(Window, Scalar, Window) -> {longStop, shortStop}", source : "// chande_kroll_stop — Chande Kroll Stop: a two-stage ATR trailing stop\n// sig: chande_kroll_stop(Window, Scalar, Window) -> {longStop, shortStop}\n// generated from musescript/indicators/lib/ChandeKrollStop.hx\n@strategy(\"ta.chande_kroll_stop\")\n@on(bar) {\n  var v = chande_kroll_stop(5, 0.5, 10);\n  plot(v.longStop, \"chande_kroll_stop.longStop\");\n  plot(v.shortStop, \"chande_kroll_stop.shortStop\");\n}\n", doc : "Chande Kroll Stop: a two-stage ATR trailing stop", file : "ChandeKrollStop.hx", argKinds : ["TWindow","TScalar","TWindow"], nativeSource : null},{ name : "chandelier_exit", sig : "chandelier_exit(Window, Scalar) -> {longStop, shortStop}", source : "// chandelier_exit — Chandelier Exit: ATR-based trailing stop anchored to the highest high / lowest low of the trailing `period` bars\n// sig: chandelier_exit(Window, Scalar) -> {longStop, shortStop}\n// generated from musescript/indicators/lib/ChandelierExit.hx\n@strategy(\"ta.chandelier_exit\")\n@on(bar) {\n  var v = chandelier_exit(5, 0.5);\n  plot(v.longStop, \"chandelier_exit.longStop\");\n  plot(v.shortStop, \"chandelier_exit.shortStop\");\n}\n", doc : "Chandelier Exit: ATR-based trailing stop anchored to the highest high / lowest low of the trailing `period` bars", file : "ChandelierExit.hx", argKinds : ["TWindow","TScalar"], nativeSource : null},{ name : "choppiness_index", sig : "choppiness_index(Window) -> Scalar", source : "// choppiness_index — Choppiness Index: how \"choppy\" (range-bound) vs\n// sig: choppiness_index(Window) -> Scalar\n// generated from musescript/indicators/lib/ChoppinessIndex.hx\n@strategy(\"ta.choppiness_index\")\n@on(bar) {\n  var v = choppiness_index(5);\n  plot(v, \"choppiness_index\");\n}\n", doc : "Choppiness Index: how \"choppy\" (range-bound) vs", file : "ChoppinessIndex.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "classic_pivots", sig : "classic_pivots() -> {r3, r2, r1, pivot, s1, s2, s3}", source : "// classic_pivots — Classic floor-trader pivots, derived from the *previous completed* bar's high/low/close — the standard textbook formula\n// sig: classic_pivots() -> {r3, r2, r1, pivot, s1, s2, s3}\n// generated from musescript/indicators/lib/ClassicPivots.hx\n@strategy(\"ta.classic_pivots\")\n@on(bar) {\n  var v = classic_pivots();\n  plot(v.r3, \"classic_pivots.r3\");\n  plot(v.r2, \"classic_pivots.r2\");\n  plot(v.r1, \"classic_pivots.r1\");\n  plot(v.pivot, \"classic_pivots.pivot\");\n  plot(v.s1, \"classic_pivots.s1\");\n  plot(v.s2, \"classic_pivots.s2\");\n  plot(v.s3, \"classic_pivots.s3\");\n}\n", doc : "Classic floor-trader pivots, derived from the *previous completed* bar's high/low/close — the standard textbook formula", file : "ClassicPivots.hx", argKinds : [], nativeSource : null},{ name : "close_vs_open", sig : "close_vs_open() -> Scalar", source : "// close_vs_open — Close vs Open: the bar's return expressed as a percentage of the open\n// sig: close_vs_open() -> Scalar\n// generated from musescript/indicators/lib/CloseVsOpen.hx\n@strategy(\"ta.close_vs_open\")\n@on(bar) {\n  var v = close_vs_open();\n  plot(v, \"close_vs_open\");\n}\n", doc : "Close vs Open: the bar's return expressed as a percentage of the open", file : "CloseVsOpen.hx", argKinds : [], nativeSource : null},{ name : "closing_marubozu", sig : "closing_marubozu(Scalar) -> Scalar", source : "// closing_marubozu — Closing Marubozu candlestick pattern — a single-bar continuation signal where price closes right at one extreme of th...\n// sig: closing_marubozu(Scalar) -> Scalar\n// generated from musescript/indicators/lib/ClosingMarubozu.hx\n@strategy(\"ta.closing_marubozu\")\n@on(bar) {\n  var v = closing_marubozu(0.5);\n  plot(v, \"closing_marubozu\");\n}\n", doc : "Closing Marubozu candlestick pattern — a single-bar continuation signal where price closes right at one extreme of th...", file : "ClosingMarubozu.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "cmf", sig : "cmf(Window) -> Scalar", source : "// cmf — Chaikin Money Flow: money-flow volume summed over a trailing window of `period` bars, normalized by total volume in t...\n// sig: cmf(Window) -> Scalar\n// generated from musescript/indicators/lib/Cmf.hx\n@strategy(\"ta.cmf\")\n@on(bar) {\n  var v = cmf(5);\n  plot(v, \"cmf\");\n}\n", doc : "Chaikin Money Flow: money-flow volume summed over a trailing window of `period` bars, normalized by total volume in t...", file : "Cmf.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "cmo", sig : "cmo(Series, Window) -> Scalar", source : "// cmo — Chande Momentum Oscillator\n// sig: cmo(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Cmo.hx\n@strategy(\"ta.cmo\")\n@on(bar) {\n  var v = cmo(close, 5);\n  plot(v, \"cmo\");\n}\n", doc : "Chande Momentum Oscillator", file : "Cmo.hx", argKinds : ["TSeries","TWindow"], nativeSource : "@indicator(\"cmo\") function(period) {\n\tif (state.hasPrev != true) {\n\t\tstate.hasPrev = true;\n\t\tstate.prevPrice = close;\n\t\tstate.gains = [];\n\t\tstate.losses = [];\n\t\tstate.sumGain = 0.0;\n\t\tstate.sumLoss = 0.0;\n\t\treturn null;\n\t}\n\tvar change = close - state.prevPrice;\n\tstate.prevPrice = close;\n\tvar gain = change > 0.0 ? change : 0.0;\n\tvar loss = change < 0.0 ? -change : 0.0;\n\n\tif (state.gains.length == period) {\n\t\tstate.sumGain = state.sumGain - state.gains[0];\n\t\tstate.sumLoss = state.sumLoss - state.losses[0];\n\t\tstate.gains.shift();\n\t\tstate.losses.shift();\n\t}\n\tstate.gains.push(gain);\n\tstate.losses.push(loss);\n\tstate.sumGain = state.sumGain + gain;\n\tstate.sumLoss = state.sumLoss + loss;\n\n\tif (state.gains.length < period) return null;\n\tvar denom = state.sumGain + state.sumLoss;\n\treturn denom == 0.0 ? 0.0 : 100.0 * (state.sumGain - state.sumLoss) / denom;\n}"},{ name : "coefficient_of_variation", sig : "coefficient_of_variation(Series, Window) -> Scalar", source : "// coefficient_of_variation — Coefficient of Variation: the trailing sample standard deviation normalized by the trailing mean, over a window of `p...\n// sig: coefficient_of_variation(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/CoefficientOfVariation.hx\n@strategy(\"ta.coefficient_of_variation\")\n@on(bar) {\n  var v = coefficient_of_variation(close, 5);\n  plot(v, \"coefficient_of_variation\");\n}\n", doc : "Coefficient of Variation: the trailing sample standard deviation normalized by the trailing mean, over a window of `p...", file : "CoefficientOfVariation.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "cointegration", sig : "cointegration(Series, Series, Window, Scalar) -> {hedge_ratio, spread, adf_stat}", source : "// cointegration\n// sig: cointegration(Series, Series, Window, Scalar) -> {hedge_ratio, spread, adf_stat}\n// generated from musescript/indicators/lib/Cointegration.hx\n@strategy(\"ta.cointegration\")\n@on(bar) {\n  var v = cointegration(close, close, 5, 0.5);\n  plot(v.hedge_ratio, \"cointegration.hedge_ratio\");\n  plot(v.spread, \"cointegration.spread\");\n  plot(v.adf_stat, \"cointegration.adf_stat\");\n}\n", doc : "", file : "Cointegration.hx", argKinds : ["TSeries","TSeries","TWindow","TScalar"], nativeSource : null},{ name : "common_sense_ratio", sig : "common_sense_ratio(Series, Window) -> Scalar", source : "// common_sense_ratio — Common Sense Ratio (Schwager/Carver)\n// sig: common_sense_ratio(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/CommonSenseRatio.hx\n@strategy(\"ta.common_sense_ratio\")\n@on(bar) {\n  var v = common_sense_ratio(close, 5);\n  plot(v, \"common_sense_ratio\");\n}\n", doc : "Common Sense Ratio (Schwager/Carver)", file : "CommonSenseRatio.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "composite_profile", sig : "composite_profile(Window, Window, Scalar) -> {poc, vah, val}", source : "// composite_profile — Composite Profile\n// sig: composite_profile(Window, Window, Scalar) -> {poc, vah, val}\n// generated from musescript/indicators/lib/CompositeProfile.hx\n@strategy(\"ta.composite_profile\")\n@on(bar) {\n  var v = composite_profile(5, 10, 0.5);\n  plot(v.poc, \"composite_profile.poc\");\n  plot(v.vah, \"composite_profile.vah\");\n  plot(v.val, \"composite_profile.val\");\n}\n", doc : "Composite Profile", file : "CompositeProfile.hx", argKinds : ["TWindow","TWindow","TScalar"], nativeSource : null},{ name : "concealing_baby_swallow", sig : "concealing_baby_swallow() -> Scalar", source : "// concealing_baby_swallow — Concealing Baby Swallow\n// sig: concealing_baby_swallow() -> Scalar\n// generated from musescript/indicators/lib/ConcealingBabySwallow.hx\n@strategy(\"ta.concealing_baby_swallow\")\n@on(bar) {\n  var v = concealing_baby_swallow();\n  plot(v, \"concealing_baby_swallow\");\n}\n", doc : "Concealing Baby Swallow", file : "ConcealingBabySwallow.hx", argKinds : [], nativeSource : null},{ name : "conditional_value_at_risk", sig : "conditional_value_at_risk(Series, Window, Scalar) -> Scalar", source : "// conditional_value_at_risk — Conditional Value at Risk (Expected Shortfall): the mean loss among the worst `(1 - confidence)` fraction of returns ...\n// sig: conditional_value_at_risk(Series, Window, Scalar) -> Scalar\n// generated from musescript/indicators/lib/ConditionalValueAtRisk.hx\n@strategy(\"ta.conditional_value_at_risk\")\n@on(bar) {\n  var v = conditional_value_at_risk(close, 5, 0.5);\n  plot(v, \"conditional_value_at_risk\");\n}\n", doc : "Conditional Value at Risk (Expected Shortfall): the mean loss among the worst `(1 - confidence)` fraction of returns ...", file : "ConditionalValueAtRisk.hx", argKinds : ["TSeries","TWindow","TScalar"], nativeSource : null},{ name : "connors_rsi", sig : "connors_rsi(Series, Window, Window, Window) -> Scalar", source : "// connors_rsi — Connors RSI: a composite short-term mean-reversion oscillator averaging three sub-signals over a trailing window\n// sig: connors_rsi(Series, Window, Window, Window) -> Scalar\n// generated from musescript/indicators/lib/ConnorsRsi.hx\n@strategy(\"ta.connors_rsi\")\n@on(bar) {\n  var v = connors_rsi(close, 5, 10, 15);\n  plot(v, \"connors_rsi\");\n}\n", doc : "Connors RSI: a composite short-term mean-reversion oscillator averaging three sub-signals over a trailing window", file : "ConnorsRsi.hx", argKinds : ["TSeries","TWindow","TWindow","TWindow"], nativeSource : null},{ name : "coppock", sig : "coppock(Series, Window, Window, Window) -> Scalar", source : "// coppock — Coppock Curve: a long-term momentum oscillator built from a WMA-smoothed sum of two rate-of-change lookbacks\n// sig: coppock(Series, Window, Window, Window) -> Scalar\n// generated from musescript/indicators/lib/Coppock.hx\n@strategy(\"ta.coppock\")\n@on(bar) {\n  var v = coppock(close, 5, 10, 15);\n  plot(v, \"coppock\");\n}\n", doc : "Coppock Curve: a long-term momentum oscillator built from a WMA-smoothed sum of two rate-of-change lookbacks", file : "Coppock.hx", argKinds : ["TSeries","TWindow","TWindow","TWindow"], nativeSource : null},{ name : "correlation_trend_indicator", sig : "correlation_trend_indicator(Series, Window) -> Scalar", source : "// correlation_trend_indicator — Ehlers' Correlation Trend Indicator: the Pearson correlation coefficient between price and a simple ascending time in...\n// sig: correlation_trend_indicator(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/CorrelationTrendIndicator.hx\n@strategy(\"ta.correlation_trend_indicator\")\n@on(bar) {\n  var v = correlation_trend_indicator(close, 5);\n  plot(v, \"correlation_trend_indicator\");\n}\n", doc : "Ehlers' Correlation Trend Indicator: the Pearson correlation coefficient between price and a simple ascending time in...", file : "CorrelationTrendIndicator.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "counterattack", sig : "counterattack(Scalar) -> Scalar", source : "// counterattack — Counterattack (a.k.a\n// sig: counterattack(Scalar) -> Scalar\n// generated from musescript/indicators/lib/Counterattack.hx\n@strategy(\"ta.counterattack\")\n@on(bar) {\n  var v = counterattack(0.5);\n  plot(v, \"counterattack\");\n}\n", doc : "Counterattack (a.k.a", file : "Counterattack.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "crab", sig : "crab() -> Scalar", source : "// crab — Crab harmonic pattern detector\n// sig: crab() -> Scalar\n// generated from musescript/indicators/lib/Crab.hx\n@strategy(\"ta.crab\")\n@on(bar) {\n  var v = crab();\n  plot(v, \"crab\");\n}\n", doc : "Crab harmonic pattern detector", file : "Crab.hx", argKinds : [], nativeSource : null},{ name : "cup_and_handle", sig : "cup_and_handle() -> Scalar", source : "// cup_and_handle — Cup-and-Handle / Inverse detector\n// sig: cup_and_handle() -> Scalar\n// generated from musescript/indicators/lib/CupAndHandle.hx\n@strategy(\"ta.cup_and_handle\")\n@on(bar) {\n  var v = cup_and_handle();\n  plot(v, \"cup_and_handle\");\n}\n", doc : "Cup-and-Handle / Inverse detector", file : "CupAndHandle.hx", argKinds : [], nativeSource : null},{ name : "cybernetic_cycle", sig : "cybernetic_cycle(Series, Scalar) -> Scalar", source : "// cybernetic_cycle — Ehlers' Cyber Cycle: a low-lag bandpass-style filter that isolates the dominant short-term cycle in price, built from...\n// sig: cybernetic_cycle(Series, Scalar) -> Scalar\n// generated from musescript/indicators/lib/CyberneticCycle.hx\n@strategy(\"ta.cybernetic_cycle\")\n@on(bar) {\n  var v = cybernetic_cycle(close, 0.5);\n  plot(v, \"cybernetic_cycle\");\n}\n", doc : "Ehlers' Cyber Cycle: a low-lag bandpass-style filter that isolates the dominant short-term cycle in price, built from...", file : "CyberneticCycle.hx", argKinds : ["TSeries","TScalar"], nativeSource : null},{ name : "cypher", sig : "cypher() -> Scalar", source : "// cypher — Cypher harmonic pattern detector\n// sig: cypher() -> Scalar\n// generated from musescript/indicators/lib/Cypher.hx\n@strategy(\"ta.cypher\")\n@on(bar) {\n  var v = cypher();\n  plot(v, \"cypher\");\n}\n", doc : "Cypher harmonic pattern detector", file : "Cypher.hx", argKinds : [], nativeSource : null},{ name : "day_of_week_profile", sig : "day_of_week_profile(Scalar) -> {bins}", source : "// day_of_week_profile — Day-of-Week Profile\n// sig: day_of_week_profile(Scalar) -> {bins}\n// generated from musescript/indicators/lib/DayOfWeekProfile.hx\n@strategy(\"ta.day_of_week_profile\")\n@on(bar) {\n  var v = day_of_week_profile(0.5);\n  plot(v.bins, \"day_of_week_profile.bins\");\n}\n", doc : "Day-of-Week Profile", file : "DayOfWeekProfile.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "decycler", sig : "decycler(Series, Window) -> Scalar", source : "// decycler — Ehlers' Decycler: price with its dominant short-cycle noise removed via a 2-pole high-pass filter, leaving only the u...\n// sig: decycler(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Decycler.hx\n@strategy(\"ta.decycler\")\n@on(bar) {\n  var v = decycler(close, 5);\n  plot(v, \"decycler\");\n}\n", doc : "Ehlers' Decycler: price with its dominant short-cycle noise removed via a 2-pole high-pass filter, leaving only the u...", file : "Decycler.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "decycler_oscillator", sig : "decycler_oscillator(Series, Window, Window) -> Scalar", source : "// decycler_oscillator — Decycler Oscillator (Ehlers): the percentage spread between two `Decycler` trend lines at different cutoff periods — ...\n// sig: decycler_oscillator(Series, Window, Window) -> Scalar\n// generated from musescript/indicators/lib/DecyclerOscillator.hx\n@strategy(\"ta.decycler_oscillator\")\n@on(bar) {\n  var v = decycler_oscillator(close, 5, 10);\n  plot(v, \"decycler_oscillator\");\n}\n", doc : "Decycler Oscillator (Ehlers): the percentage spread between two `Decycler` trend lines at different cutoff periods — ...", file : "DecyclerOscillator.hx", argKinds : ["TSeries","TWindow","TWindow"], nativeSource : null},{ name : "dema", sig : "dema(Series, Window) -> Scalar", source : "// dema — Double Exponential Moving Average (Mulloy): a reduced-lag EMA formed by running a second EMA over the first and extra...\n// sig: dema(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Dema.hx\n@strategy(\"ta.dema\")\n@on(bar) {\n  var v = dema(close, 5);\n  plot(v, \"dema\");\n}\n", doc : "Double Exponential Moving Average (Mulloy): a reduced-lag EMA formed by running a second EMA over the first and extra...", file : "Dema.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "demand_index", sig : "demand_index(Window) -> Scalar", source : "// demand_index — Demand Index (James Sibbet)\n// sig: demand_index(Window) -> Scalar\n// generated from musescript/indicators/lib/DemandIndex.hx\n@strategy(\"ta.demand_index\")\n@on(bar) {\n  var v = demand_index(5);\n  plot(v, \"demand_index\");\n}\n", doc : "Demand Index (James Sibbet)", file : "DemandIndex.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "demark_pivots", sig : "demark_pivots() -> {r1, pivot, s1}", source : "// demark_pivots — DeMark Pivots: unlike the classic/Camarilla families, the base value `X` is *conditional* on how the prior bar closed...\n// sig: demark_pivots() -> {r1, pivot, s1}\n// generated from musescript/indicators/lib/DemarkPivots.hx\n@strategy(\"ta.demark_pivots\")\n@on(bar) {\n  var v = demark_pivots();\n  plot(v.r1, \"demark_pivots.r1\");\n  plot(v.pivot, \"demark_pivots.pivot\");\n  plot(v.s1, \"demark_pivots.s1\");\n}\n", doc : "DeMark Pivots: unlike the classic/Camarilla families, the base value `X` is *conditional* on how the prior bar closed...", file : "DemarkPivots.hx", argKinds : [], nativeSource : null},{ name : "derivative_oscillator", sig : "derivative_oscillator(Series, Window, Window, Window, Window) -> Scalar", source : "// derivative_oscillator — Derivative Oscillator (Constance Brown): a double-smoothed RSI with a signal line subtracted off, isolating RSI's own...\n// sig: derivative_oscillator(Series, Window, Window, Window, Window) -> Scalar\n// generated from musescript/indicators/lib/DerivativeOscillator.hx\n@strategy(\"ta.derivative_oscillator\")\n@on(bar) {\n  var v = derivative_oscillator(close, 5, 10, 15, 20);\n  plot(v, \"derivative_oscillator\");\n}\n", doc : "Derivative Oscillator (Constance Brown): a double-smoothed RSI with a signal line subtracted off, isolating RSI's own...", file : "DerivativeOscillator.hx", argKinds : ["TSeries","TWindow","TWindow","TWindow","TWindow"], nativeSource : null},{ name : "detrended_std_dev", sig : "detrended_std_dev(Series, Window) -> Scalar", source : "// detrended_std_dev — Detrended Standard Deviation: the rolling stddev of the *detrended* price series (price minus its own trailing SMA), ...\n// sig: detrended_std_dev(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/DetrendedStdDev.hx\n@strategy(\"ta.detrended_std_dev\")\n@on(bar) {\n  var v = detrended_std_dev(close, 5);\n  plot(v, \"detrended_std_dev\");\n}\n", doc : "Detrended Standard Deviation: the rolling stddev of the *detrended* price series (price minus its own trailing SMA), ...", file : "DetrendedStdDev.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "disparity_index", sig : "disparity_index(Series, Window) -> Scalar", source : "// disparity_index — Disparity Index: how far the current price sits from its own simple moving average, as a percentage of that average\n// sig: disparity_index(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/DisparityIndex.hx\n@strategy(\"ta.disparity_index\")\n@on(bar) {\n  var v = disparity_index(close, 5);\n  plot(v, \"disparity_index\");\n}\n", doc : "Disparity Index: how far the current price sits from its own simple moving average, as a percentage of that average", file : "DisparityIndex.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "distance_ssd", sig : "distance_ssd(Series, Series, Window) -> Scalar", source : "// distance_ssd — Distance Sum of Squared Differences: the rolling sum of squared pointwise differences between two series over a trail...\n// sig: distance_ssd(Series, Series, Window) -> Scalar\n// generated from musescript/indicators/lib/DistanceSsd.hx\n@strategy(\"ta.distance_ssd\")\n@on(bar) {\n  var v = distance_ssd(close, close, 5);\n  plot(v, \"distance_ssd\");\n}\n", doc : "Distance Sum of Squared Differences: the rolling sum of squared pointwise differences between two series over a trail...", file : "DistanceSsd.hx", argKinds : ["TSeries","TSeries","TWindow"], nativeSource : null},{ name : "doji", sig : "doji(Scalar) -> Scalar", source : "// doji — Doji candlestick pattern — a single bar whose body is negligible relative to its range (open and close nearly equal),...\n// sig: doji(Scalar) -> Scalar\n// generated from musescript/indicators/lib/Doji.hx\n@strategy(\"ta.doji\")\n@on(bar) {\n  var v = doji(0.5);\n  plot(v, \"doji\");\n}\n", doc : "Doji candlestick pattern — a single bar whose body is negligible relative to its range (open and close nearly equal),...", file : "Doji.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "doji_star", sig : "doji_star(Scalar) -> Scalar", source : "// doji_star — Doji Star candlestick pattern — a 2-bar reversal where a normal-bodied candle is followed by a gapping doji, isolated...\n// sig: doji_star(Scalar) -> Scalar\n// generated from musescript/indicators/lib/DojiStar.hx\n@strategy(\"ta.doji_star\")\n@on(bar) {\n  var v = doji_star(0.5);\n  plot(v, \"doji_star\");\n}\n", doc : "Doji Star candlestick pattern — a 2-bar reversal where a normal-bodied candle is followed by a gapping doji, isolated...", file : "DojiStar.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "donchian", sig : "donchian(Window) -> {upper, middle, lower}", source : "// donchian — Donchian Channel: the highest high / lowest low over the trailing `period` bars (current bar included), with the midl...\n// sig: donchian(Window) -> {upper, middle, lower}\n// generated from musescript/indicators/lib/Donchian.hx\n@strategy(\"ta.donchian\")\n@on(bar) {\n  var v = donchian(5);\n  plot(v.upper, \"donchian.upper\");\n  plot(v.middle, \"donchian.middle\");\n  plot(v.lower, \"donchian.lower\");\n}\n", doc : "Donchian Channel: the highest high / lowest low over the trailing `period` bars (current bar included), with the midl...", file : "Donchian.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "donchian_stop", sig : "donchian_stop(Window) -> {longStop, shortStop}", source : "// donchian_stop — Donchian Stop: a trailing stop pair anchored to the highest high / lowest low of the `period` bars *strictly before* ...\n// sig: donchian_stop(Window) -> {longStop, shortStop}\n// generated from musescript/indicators/lib/DonchianStop.hx\n@strategy(\"ta.donchian_stop\")\n@on(bar) {\n  var v = donchian_stop(5);\n  plot(v.longStop, \"donchian_stop.longStop\");\n  plot(v.shortStop, \"donchian_stop.shortStop\");\n}\n", doc : "Donchian Stop: a trailing stop pair anchored to the highest high / lowest low of the `period` bars *strictly before* ...", file : "DonchianStop.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "double_bollinger", sig : "double_bollinger(Series, Window, Scalar, Scalar) -> {upper2, upper1, middle, lower1, lower2}", source : "// double_bollinger — Double Bollinger Bands: the same SMA centerline as `Bollinger`, but with two nested envelopes at different standard-d...\n// sig: double_bollinger(Series, Window, Scalar, Scalar) -> {upper2, upper1, middle, lower1, lower2}\n// generated from musescript/indicators/lib/DoubleBollinger.hx\n@strategy(\"ta.double_bollinger\")\n@on(bar) {\n  var v = double_bollinger(close, 5, 0.5, 0.5);\n  plot(v.upper2, \"double_bollinger.upper2\");\n  plot(v.upper1, \"double_bollinger.upper1\");\n  plot(v.middle, \"double_bollinger.middle\");\n  plot(v.lower1, \"double_bollinger.lower1\");\n  plot(v.lower2, \"double_bollinger.lower2\");\n}\n", doc : "Double Bollinger Bands: the same SMA centerline as `Bollinger`, but with two nested envelopes at different standard-d...", file : "DoubleBollinger.hx", argKinds : ["TSeries","TWindow","TScalar","TScalar"], nativeSource : null},{ name : "double_top_bottom", sig : "double_top_bottom() -> Scalar", source : "// double_top_bottom — Double Top / Double Bottom\n// sig: double_top_bottom() -> Scalar\n// generated from musescript/indicators/lib/DoubleTopBottom.hx\n@strategy(\"ta.double_top_bottom\")\n@on(bar) {\n  var v = double_top_bottom();\n  plot(v, \"double_top_bottom\");\n}\n", doc : "Double Top / Double Bottom", file : "DoubleTopBottom.hx", argKinds : [], nativeSource : null},{ name : "downside_gap_three_methods", sig : "downside_gap_three_methods() -> Scalar", source : "// downside_gap_three_methods — Downside Gap Three Methods candlestick pattern — a 3-bar bearish continuation: two red bars with a true gap between t...\n// sig: downside_gap_three_methods() -> Scalar\n// generated from musescript/indicators/lib/DownsideGapThreeMethods.hx\n@strategy(\"ta.downside_gap_three_methods\")\n@on(bar) {\n  var v = downside_gap_three_methods();\n  plot(v, \"downside_gap_three_methods\");\n}\n", doc : "Downside Gap Three Methods candlestick pattern — a 3-bar bearish continuation: two red bars with a true gap between t...", file : "DownsideGapThreeMethods.hx", argKinds : [], nativeSource : null},{ name : "dpo", sig : "dpo(Series, Window) -> Scalar", source : "// dpo — Detrended Price Oscillator: strips the trend component out of price by comparing an older price to a moving average c...\n// sig: dpo(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Dpo.hx\n@strategy(\"ta.dpo\")\n@on(bar) {\n  var v = dpo(close, 5);\n  plot(v, \"dpo\");\n}\n", doc : "Detrended Price Oscillator: strips the trend component out of price by comparing an older price to a moving average c...", file : "Dpo.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "dragonfly_doji", sig : "dragonfly_doji(Scalar) -> Scalar", source : "// dragonfly_doji — Dragonfly Doji candlestick pattern — a doji with a negligible upper shadow and a long lower shadow, signalling a pote...\n// sig: dragonfly_doji(Scalar) -> Scalar\n// generated from musescript/indicators/lib/DragonflyDoji.hx\n@strategy(\"ta.dragonfly_doji\")\n@on(bar) {\n  var v = dragonfly_doji(0.5);\n  plot(v, \"dragonfly_doji\");\n}\n", doc : "Dragonfly Doji candlestick pattern — a doji with a negligible upper shadow and a long lower shadow, signalling a pote...", file : "DragonflyDoji.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "drawdown_duration", sig : "drawdown_duration(Series) -> Scalar", source : "// drawdown_duration — Drawdown Duration: the number of bars since the running peak of the input (treated as an equity curve) was last set\n// sig: drawdown_duration(Series) -> Scalar\n// generated from musescript/indicators/lib/DrawdownDuration.hx\n@strategy(\"ta.drawdown_duration\")\n@on(bar) {\n  var v = drawdown_duration(close);\n  plot(v, \"drawdown_duration\");\n}\n", doc : "Drawdown Duration: the number of bars since the running peak of the input (treated as an equity curve) was last set", file : "DrawdownDuration.hx", argKinds : ["TSeries"], nativeSource : null},{ name : "dumpling_top", sig : "dumpling_top(Window) -> Scalar", source : "// dumpling_top — Dumpling Top\n// sig: dumpling_top(Window) -> Scalar\n// generated from musescript/indicators/lib/DumplingTop.hx\n@strategy(\"ta.dumpling_top\")\n@on(bar) {\n  var v = dumpling_top(5);\n  plot(v, \"dumpling_top\");\n}\n", doc : "Dumpling Top", file : "DumplingTop.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "dx", sig : "dx(Window) -> Scalar", source : "// dx — Directional Movement Index (DX): the raw, un-smoothed directional imbalance that `Adx` averages over time to produce ...\n// sig: dx(Window) -> Scalar\n// generated from musescript/indicators/lib/Dx.hx\n@strategy(\"ta.dx\")\n@on(bar) {\n  var v = dx(5);\n  plot(v, \"dx\");\n}\n", doc : "Directional Movement Index (DX): the raw, un-smoothed directional imbalance that `Adx` averages over time to produce ...", file : "Dx.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "dynamic_momentum_index", sig : "dynamic_momentum_index(Series, Window) -> Scalar", source : "// dynamic_momentum_index — Dynamic Momentum Index (Chande's volatility-adaptive RSI)\n// sig: dynamic_momentum_index(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/DynamicMomentumIndex.hx\n@strategy(\"ta.dynamic_momentum_index\")\n@on(bar) {\n  var v = dynamic_momentum_index(close, 5);\n  plot(v, \"dynamic_momentum_index\");\n}\n", doc : "Dynamic Momentum Index (Chande's volatility-adaptive RSI)", file : "DynamicMomentumIndex.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "ease_of_movement", sig : "ease_of_movement(Window) -> Scalar", source : "// ease_of_movement — Ease of Movement: relates a bar's price change to the volume needed to produce it — high volume moving price only a l...\n// sig: ease_of_movement(Window) -> Scalar\n// generated from musescript/indicators/lib/EaseOfMovement.hx\n@strategy(\"ta.ease_of_movement\")\n@on(bar) {\n  var v = ease_of_movement(5);\n  plot(v, \"ease_of_movement\");\n}\n", doc : "Ease of Movement: relates a bar's price change to the volume needed to produce it — high volume moving price only a l...", file : "EaseOfMovement.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "ehlers_stochastic", sig : "ehlers_stochastic(Series, Window) -> Scalar", source : "// ehlers_stochastic — Ehlers Stochastic\n// sig: ehlers_stochastic(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/EhlersStochastic.hx\n@strategy(\"ta.ehlers_stochastic\")\n@on(bar) {\n  var v = ehlers_stochastic(close, 5);\n  plot(v, \"ehlers_stochastic\");\n}\n", doc : "Ehlers Stochastic", file : "EhlersStochastic.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "ehma", sig : "ehma(Series, Window) -> Scalar", source : "// ehma — Exponential Hull Moving Average: the Hull MA's \"reduce lag by extrapolating from a half-period average\" construction,...\n// sig: ehma(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Ehma.hx\n@strategy(\"ta.ehma\")\n@on(bar) {\n  var v = ehma(close, 5);\n  plot(v, \"ehma\");\n}\n", doc : "Exponential Hull Moving Average: the Hull MA's \"reduce lag by extrapolating from a half-period average\" construction,...", file : "Ehma.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "elder_impulse", sig : "elder_impulse(Series, Window, Window, Window, Window) -> Scalar", source : "// elder_impulse — Elder Impulse System: colors each bar by whether both a trend EMA and a MACD histogram are simultaneously rising, fal...\n// sig: elder_impulse(Series, Window, Window, Window, Window) -> Scalar\n// generated from musescript/indicators/lib/ElderImpulse.hx\n@strategy(\"ta.elder_impulse\")\n@on(bar) {\n  var v = elder_impulse(close, 5, 10, 15, 20);\n  plot(v, \"elder_impulse\");\n}\n", doc : "Elder Impulse System: colors each bar by whether both a trend EMA and a MACD histogram are simultaneously rising, fal...", file : "ElderImpulse.hx", argKinds : ["TSeries","TWindow","TWindow","TWindow","TWindow"], nativeSource : null},{ name : "elder_ray", sig : "elder_ray(Window) -> {bull, bear}", source : "// elder_ray — Elder Ray: measures how far buyers pushed price above (bull power) and sellers pushed price below (bear power) a tren...\n// sig: elder_ray(Window) -> {bull, bear}\n// generated from musescript/indicators/lib/ElderRay.hx\n@strategy(\"ta.elder_ray\")\n@on(bar) {\n  var v = elder_ray(5);\n  plot(v.bull, \"elder_ray.bull\");\n  plot(v.bear, \"elder_ray.bear\");\n}\n", doc : "Elder Ray: measures how far buyers pushed price above (bull power) and sellers pushed price below (bear power) a tren...", file : "ElderRay.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "elder_safezone", sig : "elder_safezone(Window, Scalar) -> {longStop, shortStop}", source : "// elder_safezone — Elder's SafeZone stop: a volatility-aware trailing stop built from the *average size of adverse penetrations* below t...\n// sig: elder_safezone(Window, Scalar) -> {longStop, shortStop}\n// generated from musescript/indicators/lib/ElderSafezone.hx\n@strategy(\"ta.elder_safezone\")\n@on(bar) {\n  var v = elder_safezone(5, 0.5);\n  plot(v.longStop, \"elder_safezone.longStop\");\n  plot(v.shortStop, \"elder_safezone.shortStop\");\n}\n", doc : "Elder's SafeZone stop: a volatility-aware trailing stop built from the *average size of adverse penetrations* below t...", file : "ElderSafezone.hx", argKinds : ["TWindow","TScalar"], nativeSource : null},{ name : "empirical_mode_decomposition", sig : "empirical_mode_decomposition(Window, Scalar) -> Scalar", source : "// empirical_mode_decomposition — Ehlers Empirical Mode Decomposition (EMD)\n// sig: empirical_mode_decomposition(Window, Scalar) -> Scalar\n// generated from musescript/indicators/lib/EmpiricalModeDecomposition.hx\n@strategy(\"ta.empirical_mode_decomposition\")\n@on(bar) {\n  var v = empirical_mode_decomposition(5, 0.5);\n  plot(v, \"empirical_mode_decomposition\");\n}\n", doc : "Ehlers Empirical Mode Decomposition (EMD)", file : "EmpiricalModeDecomposition.hx", argKinds : ["TWindow","TScalar"], nativeSource : null},{ name : "engulfing", sig : "engulfing() -> Scalar", source : "// engulfing — Engulfing candlestick pattern — a 2-bar reversal where the second bar's body fully contains the first bar's body and ...\n// sig: engulfing() -> Scalar\n// generated from musescript/indicators/lib/Engulfing.hx\n@strategy(\"ta.engulfing\")\n@on(bar) {\n  var v = engulfing();\n  plot(v, \"engulfing\");\n}\n", doc : "Engulfing candlestick pattern — a 2-bar reversal where the second bar's body fully contains the first bar's body and ...", file : "Engulfing.hx", argKinds : [], nativeSource : null},{ name : "equivolume", sig : "equivolume(Window) -> {height, width}", source : "// equivolume — Equivolume\n// sig: equivolume(Window) -> {height, width}\n// generated from musescript/indicators/lib/Equivolume.hx\n@strategy(\"ta.equivolume\")\n@on(bar) {\n  var v = equivolume(5);\n  plot(v.height, \"equivolume.height\");\n  plot(v.width, \"equivolume.width\");\n}\n", doc : "Equivolume", file : "Equivolume.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "even_better_sinewave", sig : "even_better_sinewave(Window, Window) -> Scalar", source : "// even_better_sinewave — Ehlers Even Better Sinewave (EBSW)\n// sig: even_better_sinewave(Window, Window) -> Scalar\n// generated from musescript/indicators/lib/EvenBetterSinewave.hx\n@strategy(\"ta.even_better_sinewave\")\n@on(bar) {\n  var v = even_better_sinewave(5, 10);\n  plot(v, \"even_better_sinewave\");\n}\n", doc : "Ehlers Even Better Sinewave (EBSW)", file : "EvenBetterSinewave.hx", argKinds : ["TWindow","TWindow"], nativeSource : null},{ name : "evening_doji_star", sig : "evening_doji_star(Scalar) -> Scalar", source : "// evening_doji_star — Evening Doji Star candlestick pattern — a 3-bar bearish reversal: a strong green bar, a gapping doji, then a red bar ...\n// sig: evening_doji_star(Scalar) -> Scalar\n// generated from musescript/indicators/lib/EveningDojiStar.hx\n@strategy(\"ta.evening_doji_star\")\n@on(bar) {\n  var v = evening_doji_star(0.5);\n  plot(v, \"evening_doji_star\");\n}\n", doc : "Evening Doji Star candlestick pattern — a 3-bar bearish reversal: a strong green bar, a gapping doji, then a red bar ...", file : "EveningDojiStar.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "evwma", sig : "evwma(Window) -> Scalar", source : "// evwma — Elastic Volume Weighted Moving Average: an EMA-style recursion whose decay factor is driven by each bar's own volume ...\n// sig: evwma(Window) -> Scalar\n// generated from musescript/indicators/lib/Evwma.hx\n@strategy(\"ta.evwma\")\n@on(bar) {\n  var v = evwma(5);\n  plot(v, \"evwma\");\n}\n", doc : "Elastic Volume Weighted Moving Average: an EMA-style recursion whose decay factor is driven by each bar's own volume ...", file : "Evwma.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "ewma_volatility", sig : "ewma_volatility(Series, Scalar) -> Scalar", source : "// ewma_volatility — EWMA Volatility (RiskMetrics-style): an exponentially-weighted running variance of log-returns, more responsive to re...\n// sig: ewma_volatility(Series, Scalar) -> Scalar\n// generated from musescript/indicators/lib/EwmaVolatility.hx\n@strategy(\"ta.ewma_volatility\")\n@on(bar) {\n  var v = ewma_volatility(close, 0.5);\n  plot(v, \"ewma_volatility\");\n}\n", doc : "EWMA Volatility (RiskMetrics-style): an exponentially-weighted running variance of log-returns, more responsive to re...", file : "EwmaVolatility.hx", argKinds : ["TSeries","TScalar"], nativeSource : null},{ name : "expectancy", sig : "expectancy(Series, Window) -> Scalar", source : "// expectancy — Trade Expectancy (Van Tharp): the average result per trade, expressed in units of the average loss, over a trailing w...\n// sig: expectancy(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Expectancy.hx\n@strategy(\"ta.expectancy\")\n@on(bar) {\n  var v = expectancy(close, 5);\n  plot(v, \"expectancy\");\n}\n", doc : "Trade Expectancy (Van Tharp): the average result per trade, expressed in units of the average loss, over a trailing w...", file : "Expectancy.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "falling_three_methods", sig : "falling_three_methods() -> Scalar", source : "// falling_three_methods — Falling Three Methods candlestick pattern — a 5-bar bearish continuation: a long down bar, three small consolidation ...\n// sig: falling_three_methods() -> Scalar\n// generated from musescript/indicators/lib/FallingThreeMethods.hx\n@strategy(\"ta.falling_three_methods\")\n@on(bar) {\n  var v = falling_three_methods();\n  plot(v, \"falling_three_methods\");\n}\n", doc : "Falling Three Methods candlestick pattern — a 5-bar bearish continuation: a long down bar, three small consolidation ...", file : "FallingThreeMethods.hx", argKinds : [], nativeSource : null},{ name : "fama", sig : "fama(Series, Scalar, Scalar) -> Scalar", source : "// fama — FAMA (Following Adaptive Moving Average)\n// sig: fama(Series, Scalar, Scalar) -> Scalar\n// generated from musescript/indicators/lib/Fama.hx\n@strategy(\"ta.fama\")\n@on(bar) {\n  var v = fama(close, 0.5, 0.5);\n  plot(v, \"fama\");\n}\n", doc : "FAMA (Following Adaptive Moving Average)", file : "Fama.hx", argKinds : ["TSeries","TScalar","TScalar"], nativeSource : null},{ name : "fib_arcs", sig : "fib_arcs() -> {arc382, arc500, arc618}", source : "// fib_arcs — Fibonacci Arcs\n// sig: fib_arcs() -> {arc382, arc500, arc618}\n// generated from musescript/indicators/lib/FibArcs.hx\n@strategy(\"ta.fib_arcs\")\n@on(bar) {\n  var v = fib_arcs();\n  plot(v.arc382, \"fib_arcs.arc382\");\n  plot(v.arc500, \"fib_arcs.arc500\");\n  plot(v.arc618, \"fib_arcs.arc618\");\n}\n", doc : "Fibonacci Arcs", file : "FibArcs.hx", argKinds : [], nativeSource : null},{ name : "fib_channel", sig : "fib_channel() -> {base, level618, level1000, level1618}", source : "// fib_channel — Fibonacci Channel\n// sig: fib_channel() -> {base, level618, level1000, level1618}\n// generated from musescript/indicators/lib/FibChannel.hx\n@strategy(\"ta.fib_channel\")\n@on(bar) {\n  var v = fib_channel();\n  plot(v.base, \"fib_channel.base\");\n  plot(v.level618, \"fib_channel.level618\");\n  plot(v.level1000, \"fib_channel.level1000\");\n  plot(v.level1618, \"fib_channel.level1618\");\n}\n", doc : "Fibonacci Channel", file : "FibChannel.hx", argKinds : [], nativeSource : null},{ name : "fib_confluence", sig : "fib_confluence() -> {price, strength}", source : "// fib_confluence — Fibonacci Confluence — the strongest retracement cluster across recent legs\n// sig: fib_confluence() -> {price, strength}\n// generated from musescript/indicators/lib/FibConfluence.hx\n@strategy(\"ta.fib_confluence\")\n@on(bar) {\n  var v = fib_confluence();\n  plot(v.price, \"fib_confluence.price\");\n  plot(v.strength, \"fib_confluence.strength\");\n}\n", doc : "Fibonacci Confluence — the strongest retracement cluster across recent legs", file : "FibConfluence.hx", argKinds : [], nativeSource : null},{ name : "fib_extension", sig : "fib_extension(Window) -> {level0, level618, level1000, level1618, level2618}", source : "// fib_extension — Fibonacci Extension: projects the classic extension ratios beyond the highest high of the trailing `period` bars, sca...\n// sig: fib_extension(Window) -> {level0, level618, level1000, level1618, level2618}\n// generated from musescript/indicators/lib/FibExtension.hx\n@strategy(\"ta.fib_extension\")\n@on(bar) {\n  var v = fib_extension(5);\n  plot(v.level0, \"fib_extension.level0\");\n  plot(v.level618, \"fib_extension.level618\");\n  plot(v.level1000, \"fib_extension.level1000\");\n  plot(v.level1618, \"fib_extension.level1618\");\n  plot(v.level2618, \"fib_extension.level2618\");\n}\n", doc : "Fibonacci Extension: projects the classic extension ratios beyond the highest high of the trailing `period` bars, sca...", file : "FibExtension.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "fib_fan", sig : "fib_fan() -> {fan382, fan500, fan618}", source : "// fib_fan — Fibonacci Fan — trendlines fanning from a swing start through the retracement levels at the swing end, extended to th...\n// sig: fib_fan() -> {fan382, fan500, fan618}\n// generated from musescript/indicators/lib/FibFan.hx\n@strategy(\"ta.fib_fan\")\n@on(bar) {\n  var v = fib_fan();\n  plot(v.fan382, \"fib_fan.fan382\");\n  plot(v.fan500, \"fib_fan.fan500\");\n  plot(v.fan618, \"fib_fan.fan618\");\n}\n", doc : "Fibonacci Fan — trendlines fanning from a swing start through the retracement levels at the swing end, extended to th...", file : "FibFan.hx", argKinds : [], nativeSource : null},{ name : "fib_projection", sig : "fib_projection() -> {level618, level1000, level1618, level2618}", source : "// fib_projection — Fibonacci Projection — a measured move from the last three swing pivots\n// sig: fib_projection() -> {level618, level1000, level1618, level2618}\n// generated from musescript/indicators/lib/FibProjection.hx\n@strategy(\"ta.fib_projection\")\n@on(bar) {\n  var v = fib_projection();\n  plot(v.level618, \"fib_projection.level618\");\n  plot(v.level1000, \"fib_projection.level1000\");\n  plot(v.level1618, \"fib_projection.level1618\");\n  plot(v.level2618, \"fib_projection.level2618\");\n}\n", doc : "Fibonacci Projection — a measured move from the last three swing pivots", file : "FibProjection.hx", argKinds : [], nativeSource : null},{ name : "fib_retracement", sig : "fib_retracement(Window) -> {level0, level236, level382, level500, level618, level786, level1000}", source : "// fib_retracement — Fibonacci Retracement: the standard retracement ladder between the highest high and lowest low of the trailing `perio...\n// sig: fib_retracement(Window) -> {level0, level236, level382, level500, level618, level786, level1000}\n// generated from musescript/indicators/lib/FibRetracement.hx\n@strategy(\"ta.fib_retracement\")\n@on(bar) {\n  var v = fib_retracement(5);\n  plot(v.level0, \"fib_retracement.level0\");\n  plot(v.level236, \"fib_retracement.level236\");\n  plot(v.level382, \"fib_retracement.level382\");\n  plot(v.level500, \"fib_retracement.level500\");\n  plot(v.level618, \"fib_retracement.level618\");\n  plot(v.level786, \"fib_retracement.level786\");\n  plot(v.level1000, \"fib_retracement.level1000\");\n}\n", doc : "Fibonacci Retracement: the standard retracement ladder between the highest high and lowest low of the trailing `perio...", file : "FibRetracement.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "fib_time_zones", sig : "fib_time_zones() -> {onZone, barsToNext}", source : "// fib_time_zones — Fibonacci Time Zones — vertical markers at Fibonacci bar-distances from the most recent swing pivot\n// sig: fib_time_zones() -> {onZone, barsToNext}\n// generated from musescript/indicators/lib/FibTimeZones.hx\n@strategy(\"ta.fib_time_zones\")\n@on(bar) {\n  var v = fib_time_zones();\n  plot(v.onZone, \"fib_time_zones.onZone\");\n  plot(v.barsToNext, \"fib_time_zones.barsToNext\");\n}\n", doc : "Fibonacci Time Zones — vertical markers at Fibonacci bar-distances from the most recent swing pivot", file : "FibTimeZones.hx", argKinds : [], nativeSource : null},{ name : "fibonacci_pivots", sig : "fibonacci_pivots() -> {r3, r2, r1, pivot, s1, s2, s3}", source : "// fibonacci_pivots — Fibonacci Pivots: the classic (H+L+C)/3 pivot, with support/resistance offsets scaled by Fibonacci ratios of the prio...\n// sig: fibonacci_pivots() -> {r3, r2, r1, pivot, s1, s2, s3}\n// generated from musescript/indicators/lib/FibonacciPivots.hx\n@strategy(\"ta.fibonacci_pivots\")\n@on(bar) {\n  var v = fibonacci_pivots();\n  plot(v.r3, \"fibonacci_pivots.r3\");\n  plot(v.r2, \"fibonacci_pivots.r2\");\n  plot(v.r1, \"fibonacci_pivots.r1\");\n  plot(v.pivot, \"fibonacci_pivots.pivot\");\n  plot(v.s1, \"fibonacci_pivots.s1\");\n  plot(v.s2, \"fibonacci_pivots.s2\");\n  plot(v.s3, \"fibonacci_pivots.s3\");\n}\n", doc : "Fibonacci Pivots: the classic (H+L+C)/3 pivot, with support/resistance offsets scaled by Fibonacci ratios of the prio...", file : "FibonacciPivots.hx", argKinds : [], nativeSource : null},{ name : "fisher_rsi", sig : "fisher_rsi(Series, Window, Window) -> Scalar", source : "// fisher_rsi — Fisher-transformed RSI: applies the same Fisher Transform machinery (see `FisherTransform`) to a Wilder RSI series in...\n// sig: fisher_rsi(Series, Window, Window) -> Scalar\n// generated from musescript/indicators/lib/FisherRsi.hx\n@strategy(\"ta.fisher_rsi\")\n@on(bar) {\n  var v = fisher_rsi(close, 5, 10);\n  plot(v, \"fisher_rsi\");\n}\n", doc : "Fisher-transformed RSI: applies the same Fisher Transform machinery (see `FisherTransform`) to a Wilder RSI series in...", file : "FisherRsi.hx", argKinds : ["TSeries","TWindow","TWindow"], nativeSource : null},{ name : "fisher_transform", sig : "fisher_transform(Series, Window) -> Scalar", source : "// fisher_transform — Ehlers' Fisher Transform: maps a rolling min-max-normalized price into a Gaussian-ish distribution, sharpening turnin...\n// sig: fisher_transform(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/FisherTransform.hx\n@strategy(\"ta.fisher_transform\")\n@on(bar) {\n  var v = fisher_transform(close, 5);\n  plot(v, \"fisher_transform\");\n}\n", doc : "Ehlers' Fisher Transform: maps a rolling min-max-normalized price into a Gaussian-ish distribution, sharpening turnin...", file : "FisherTransform.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "flag_pennant", sig : "flag_pennant() -> Scalar", source : "// flag_pennant — Flag / Pennant continuation chart pattern\n// sig: flag_pennant() -> Scalar\n// generated from musescript/indicators/lib/FlagPennant.hx\n@strategy(\"ta.flag_pennant\")\n@on(bar) {\n  var v = flag_pennant();\n  plot(v, \"flag_pennant\");\n}\n", doc : "Flag / Pennant continuation chart pattern", file : "FlagPennant.hx", argKinds : [], nativeSource : null},{ name : "force_index", sig : "force_index(Window) -> Scalar", source : "// force_index — Force Index: combines a bar's price change and volume into a single momentum/volume measure, smoothed with an EMA\n// sig: force_index(Window) -> Scalar\n// generated from musescript/indicators/lib/ForceIndex.hx\n@strategy(\"ta.force_index\")\n@on(bar) {\n  var v = force_index(5);\n  plot(v, \"force_index\");\n}\n", doc : "Force Index: combines a bar's price change and volume into a single momentum/volume measure, smoothed with an EMA", file : "ForceIndex.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "fourier_decompose", sig : "fourier_decompose(Series, Window, Scalar) -> Scalar", source : "// fourier_decompose — Fourier decomposition of the trailing price window — a MuseScript-native builtin (not a Wickra port; see FourierMath ...\n// sig: fourier_decompose(Series, Window, Scalar) -> Scalar\n// generated from musescript/indicators/lib/FourierDecompose.hx\n@strategy(\"ta.fourier_decompose\")\n@on(bar) {\n  var v = fourier_decompose(close, 5, 0.5);\n  plot(v, \"fourier_decompose\");\n}\n", doc : "Fourier decomposition of the trailing price window — a MuseScript-native builtin (not a Wickra port; see FourierMath ...", file : "FourierDecompose.hx", argKinds : ["TSeries","TWindow","TScalar"], nativeSource : null},{ name : "fourier_dominant_period", sig : "fourier_dominant_period(Series, Window) -> Scalar", source : "// fourier_dominant_period — Dominant cycle length via windowed DFT — a MuseScript-native builtin (not a Wickra port; see FourierMath)\n// sig: fourier_dominant_period(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/FourierDominantPeriod.hx\n@strategy(\"ta.fourier_dominant_period\")\n@on(bar) {\n  var v = fourier_dominant_period(close, 5);\n  plot(v, \"fourier_dominant_period\");\n}\n", doc : "Dominant cycle length via windowed DFT — a MuseScript-native builtin (not a Wickra port; see FourierMath)", file : "FourierDominantPeriod.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "fourier_projection", sig : "fourier_projection(Series, Window, Scalar, Scalar, Bool) -> Scalar", source : "// fourier_projection — Fourier-based price projection — a MuseScript-native builtin (not a Wickra port; see FourierMath for the shared DFT)\n// sig: fourier_projection(Series, Window, Scalar, Scalar, Bool) -> Scalar\n// generated from musescript/indicators/lib/FourierProjection.hx\n@strategy(\"ta.fourier_projection\")\n@on(bar) {\n  var v = fourier_projection(close, 5, 0.5, 0.5, true);\n  plot(v, \"fourier_projection\");\n}\n", doc : "Fourier-based price projection — a MuseScript-native builtin (not a Wickra port; see FourierMath for the shared DFT)", file : "FourierProjection.hx", argKinds : ["TSeries","TWindow","TScalar","TScalar","TBool"], nativeSource : null},{ name : "fourier_recompose", sig : "fourier_recompose(Series, Window, Scalar) -> Scalar", source : "// fourier_recompose — Fourier recomposition (low-pass resynthesis) of the trailing price window — a MuseScript-native builtin (not a Wickra...\n// sig: fourier_recompose(Series, Window, Scalar) -> Scalar\n// generated from musescript/indicators/lib/FourierRecompose.hx\n@strategy(\"ta.fourier_recompose\")\n@on(bar) {\n  var v = fourier_recompose(close, 5, 0.5);\n  plot(v, \"fourier_recompose\");\n}\n", doc : "Fourier recomposition (low-pass resynthesis) of the trailing price window — a MuseScript-native builtin (not a Wickra...", file : "FourierRecompose.hx", argKinds : ["TSeries","TWindow","TScalar"], nativeSource : null},{ name : "fractal_chaos_bands", sig : "fractal_chaos_bands() -> {upper, lower}", source : "// fractal_chaos_bands — Fractal Chaos Bands (Bill Williams): bands held at the most recently *confirmed* 5-bar fractal high/low, updating onl...\n// sig: fractal_chaos_bands() -> {upper, lower}\n// generated from musescript/indicators/lib/FractalChaosBands.hx\n@strategy(\"ta.fractal_chaos_bands\")\n@on(bar) {\n  var v = fractal_chaos_bands();\n  plot(v.upper, \"fractal_chaos_bands.upper\");\n  plot(v.lower, \"fractal_chaos_bands.lower\");\n}\n", doc : "Fractal Chaos Bands (Bill Williams): bands held at the most recently *confirmed* 5-bar fractal high/low, updating onl...", file : "FractalChaosBands.hx", argKinds : [], nativeSource : null},{ name : "frama", sig : "frama(Series, Window) -> Scalar", source : "// frama — Fractal Adaptive Moving Average (Ehlers): an EMA-style average whose decay factor is driven bar-by-bar by an estimate...\n// sig: frama(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Frama.hx\n@strategy(\"ta.frama\")\n@on(bar) {\n  var v = frama(close, 5);\n  plot(v, \"frama\");\n}\n", doc : "Fractal Adaptive Moving Average (Ehlers): an EMA-style average whose decay factor is driven bar-by-bar by an estimate...", file : "Frama.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "fry_pan_bottom", sig : "fry_pan_bottom(Window) -> Scalar", source : "// fry_pan_bottom — Frying Pan Bottom\n// sig: fry_pan_bottom(Window) -> Scalar\n// generated from musescript/indicators/lib/FryPanBottom.hx\n@strategy(\"ta.fry_pan_bottom\")\n@on(bar) {\n  var v = fry_pan_bottom(5);\n  plot(v, \"fry_pan_bottom\");\n}\n", doc : "Frying Pan Bottom", file : "FryPanBottom.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "gain_loss_ratio", sig : "gain_loss_ratio(Series, Window) -> Scalar", source : "// gain_loss_ratio — Gain/Loss Ratio: the simple (non-Wilder) rolling ratio of average gain to average loss over a trailing window of `per...\n// sig: gain_loss_ratio(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/GainLossRatio.hx\n@strategy(\"ta.gain_loss_ratio\")\n@on(bar) {\n  var v = gain_loss_ratio(close, 5);\n  plot(v, \"gain_loss_ratio\");\n}\n", doc : "Gain/Loss Ratio: the simple (non-Wilder) rolling ratio of average gain to average loss over a trailing window of `per...", file : "GainLossRatio.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "gain_to_pain_ratio", sig : "gain_to_pain_ratio(Series, Window) -> Scalar", source : "// gain_to_pain_ratio — Gain to Pain Ratio (Schwager): the sum of all bar-over-bar returns over a trailing window of `period` bars, divided b...\n// sig: gain_to_pain_ratio(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/GainToPainRatio.hx\n@strategy(\"ta.gain_to_pain_ratio\")\n@on(bar) {\n  var v = gain_to_pain_ratio(close, 5);\n  plot(v, \"gain_to_pain_ratio\");\n}\n", doc : "Gain to Pain Ratio (Schwager): the sum of all bar-over-bar returns over a trailing window of `period` bars, divided b...", file : "GainToPainRatio.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "gap_side_by_side_white", sig : "gap_side_by_side_white(Scalar) -> Scalar", source : "// gap_side_by_side_white — Gap Side-by-Side White Lines candlestick pattern — a 3-bar continuation signal: a trend bar gaps, then two consecutiv...\n// sig: gap_side_by_side_white(Scalar) -> Scalar\n// generated from musescript/indicators/lib/GapSideBySideWhite.hx\n@strategy(\"ta.gap_side_by_side_white\")\n@on(bar) {\n  var v = gap_side_by_side_white(0.5);\n  plot(v, \"gap_side_by_side_white\");\n}\n", doc : "Gap Side-by-Side White Lines candlestick pattern — a 3-bar continuation signal: a trend bar gaps, then two consecutiv...", file : "GapSideBySideWhite.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "garch11", sig : "garch11(Series, Scalar, Scalar, Scalar) -> Scalar", source : "// garch11 — GARCH(1,1) conditional volatility\n// sig: garch11(Series, Scalar, Scalar, Scalar) -> Scalar\n// generated from musescript/indicators/lib/Garch11.hx\n@strategy(\"ta.garch11\")\n@on(bar) {\n  var v = garch11(close, 0.5, 0.5, 0.5);\n  plot(v, \"garch11\");\n}\n", doc : "GARCH(1,1) conditional volatility", file : "Garch11.hx", argKinds : ["TSeries","TScalar","TScalar","TScalar"], nativeSource : null},{ name : "garman_klass", sig : "garman_klass(Window) -> Scalar", source : "// garman_klass — Garman-Klass volatility estimator: a more efficient realized-volatility estimate than close-to-close stddev, since it...\n// sig: garman_klass(Window) -> Scalar\n// generated from musescript/indicators/lib/GarmanKlass.hx\n@strategy(\"ta.garman_klass\")\n@on(bar) {\n  var v = garman_klass(5);\n  plot(v, \"garman_klass\");\n}\n", doc : "Garman-Klass volatility estimator: a more efficient realized-volatility estimate than close-to-close stddev, since it...", file : "GarmanKlass.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "gartley", sig : "gartley() -> Scalar", source : "// gartley — Gartley harmonic pattern detector\n// sig: gartley() -> Scalar\n// generated from musescript/indicators/lib/Gartley.hx\n@strategy(\"ta.gartley\")\n@on(bar) {\n  var v = gartley();\n  plot(v, \"gartley\");\n}\n", doc : "Gartley harmonic pattern detector", file : "Gartley.hx", argKinds : [], nativeSource : null},{ name : "gator_oscillator", sig : "gator_oscillator(Window, Window, Window) -> {upper, lower}", source : "// gator_oscillator — Gator Oscillator: the absolute convergence/divergence of Bill Williams' Alligator lines, split into an upper bar (jaw vs\n// sig: gator_oscillator(Window, Window, Window) -> {upper, lower}\n// generated from musescript/indicators/lib/GatorOscillator.hx\n@strategy(\"ta.gator_oscillator\")\n@on(bar) {\n  var v = gator_oscillator(5, 10, 15);\n  plot(v.upper, \"gator_oscillator.upper\");\n  plot(v.lower, \"gator_oscillator.lower\");\n}\n", doc : "Gator Oscillator: the absolute convergence/divergence of Bill Williams' Alligator lines, split into an upper bar (jaw vs", file : "GatorOscillator.hx", argKinds : ["TWindow","TWindow","TWindow"], nativeSource : null},{ name : "generalized_dema", sig : "generalized_dema(Series, Window, Scalar) -> Scalar", source : "// generalized_dema — Generalized DEMA: DEMA with a tunable \"volume factor\" `v` controlling how aggressively lag is extrapolated away\n// sig: generalized_dema(Series, Window, Scalar) -> Scalar\n// generated from musescript/indicators/lib/GeneralizedDema.hx\n@strategy(\"ta.generalized_dema\")\n@on(bar) {\n  var v = generalized_dema(close, 5, 0.5);\n  plot(v, \"generalized_dema\");\n}\n", doc : "Generalized DEMA: DEMA with a tunable \"volume factor\" `v` controlling how aggressively lag is extrapolated away", file : "GeneralizedDema.hx", argKinds : ["TSeries","TWindow","TScalar"], nativeSource : null},{ name : "geometric_ma", sig : "geometric_ma(Series, Window) -> Scalar", source : "// geometric_ma — Geometric Moving Average: the rolling geometric mean of the trailing `period` values, computed via a sum-of-logs to s...\n// sig: geometric_ma(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/GeometricMa.hx\n@strategy(\"ta.geometric_ma\")\n@on(bar) {\n  var v = geometric_ma(close, 5);\n  plot(v, \"geometric_ma\");\n}\n", doc : "Geometric Moving Average: the rolling geometric mean of the trailing `period` values, computed via a sum-of-logs to s...", file : "GeometricMa.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "golden_pocket", sig : "golden_pocket() -> {low, mid, high}", source : "// golden_pocket — Golden Pocket\n// sig: golden_pocket() -> {low, mid, high}\n// generated from musescript/indicators/lib/GoldenPocket.hx\n@strategy(\"ta.golden_pocket\")\n@on(bar) {\n  var v = golden_pocket();\n  plot(v.low, \"golden_pocket.low\");\n  plot(v.mid, \"golden_pocket.mid\");\n  plot(v.high, \"golden_pocket.high\");\n}\n", doc : "Golden Pocket", file : "GoldenPocket.hx", argKinds : [], nativeSource : null},{ name : "granger_causality", sig : "granger_causality(Series, Series, Window, Window) -> Scalar", source : "// granger_causality — Granger causality F-statistic\n// sig: granger_causality(Series, Series, Window, Window) -> Scalar\n// generated from musescript/indicators/lib/GrangerCausality.hx\n@strategy(\"ta.granger_causality\")\n@on(bar) {\n  var v = granger_causality(close, close, 5, 10);\n  plot(v, \"granger_causality\");\n}\n", doc : "Granger causality F-statistic", file : "GrangerCausality.hx", argKinds : ["TSeries","TSeries","TWindow","TWindow"], nativeSource : null},{ name : "gravestone_doji", sig : "gravestone_doji(Scalar) -> Scalar", source : "// gravestone_doji — Gravestone Doji candlestick pattern — a doji with a negligible lower shadow and a long upper shadow, the mirror image...\n// sig: gravestone_doji(Scalar) -> Scalar\n// generated from musescript/indicators/lib/GravestoneDoji.hx\n@strategy(\"ta.gravestone_doji\")\n@on(bar) {\n  var v = gravestone_doji(0.5);\n  plot(v, \"gravestone_doji\");\n}\n", doc : "Gravestone Doji candlestick pattern — a doji with a negligible lower shadow and a long upper shadow, the mirror image...", file : "GravestoneDoji.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "hammer", sig : "hammer(Window) -> Scalar", source : "// hammer — Hammer candlestick pattern — a bullish reversal shape (small body near the top of the range, negligible upper shadow,...\n// sig: hammer(Window) -> Scalar\n// generated from musescript/indicators/lib/Hammer.hx\n@strategy(\"ta.hammer\")\n@on(bar) {\n  var v = hammer(5);\n  plot(v, \"hammer\");\n}\n", doc : "Hammer candlestick pattern — a bullish reversal shape (small body near the top of the range, negligible upper shadow,...", file : "Hammer.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "hanging_man", sig : "hanging_man(Window) -> Scalar", source : "// hanging_man — Hanging Man candlestick pattern — geometrically identical to `Hammer` (small body near the top, negligible upper shad...\n// sig: hanging_man(Window) -> Scalar\n// generated from musescript/indicators/lib/HangingMan.hx\n@strategy(\"ta.hanging_man\")\n@on(bar) {\n  var v = hanging_man(5);\n  plot(v, \"hanging_man\");\n}\n", doc : "Hanging Man candlestick pattern — geometrically identical to `Hammer` (small body near the top, negligible upper shad...", file : "HangingMan.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "harami", sig : "harami() -> Scalar", source : "// harami — Harami candlestick pattern — a 2-bar reversal where the second bar's body is fully *contained inside* the first bar's...\n// sig: harami() -> Scalar\n// generated from musescript/indicators/lib/Harami.hx\n@strategy(\"ta.harami\")\n@on(bar) {\n  var v = harami();\n  plot(v, \"harami\");\n}\n", doc : "Harami candlestick pattern — a 2-bar reversal where the second bar's body is fully *contained inside* the first bar's...", file : "Harami.hx", argKinds : [], nativeSource : null},{ name : "harami_cross", sig : "harami_cross(Scalar) -> Scalar", source : "// harami_cross — Harami Cross candlestick pattern — a `Harami` where the second bar is specifically a doji, an even stronger indecisio...\n// sig: harami_cross(Scalar) -> Scalar\n// generated from musescript/indicators/lib/HaramiCross.hx\n@strategy(\"ta.harami_cross\")\n@on(bar) {\n  var v = harami_cross(0.5);\n  plot(v, \"harami_cross\");\n}\n", doc : "Harami Cross candlestick pattern — a `Harami` where the second bar is specifically a doji, an even stronger indecisio...", file : "HaramiCross.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "hasbrouck_information_share", sig : "hasbrouck_information_share(Series, Series, Window) -> Scalar", source : "// hasbrouck_information_share — Hasbrouck Information Share\n// sig: hasbrouck_information_share(Series, Series, Window) -> Scalar\n// generated from musescript/indicators/lib/HasbrouckInformationShare.hx\n@strategy(\"ta.hasbrouck_information_share\")\n@on(bar) {\n  var v = hasbrouck_information_share(close, close, 5);\n  plot(v, \"hasbrouck_information_share\");\n}\n", doc : "Hasbrouck Information Share", file : "HasbrouckInformationShare.hx", argKinds : ["TSeries","TSeries","TWindow"], nativeSource : null},{ name : "head_and_shoulders", sig : "head_and_shoulders() -> Scalar", source : "// head_and_shoulders — Head-and-Shoulders / Inverse detector\n// sig: head_and_shoulders() -> Scalar\n// generated from musescript/indicators/lib/HeadAndShoulders.hx\n@strategy(\"ta.head_and_shoulders\")\n@on(bar) {\n  var v = head_and_shoulders();\n  plot(v, \"head_and_shoulders\");\n}\n", doc : "Head-and-Shoulders / Inverse detector", file : "HeadAndShoulders.hx", argKinds : [], nativeSource : null},{ name : "heikin_ashi", sig : "heikin_ashi() -> {open, high, low, close}", source : "// heikin_ashi — Heikin-Ashi: a smoothed synthetic candle series that filters out noise by averaging each bar with the running synthet...\n// sig: heikin_ashi() -> {open, high, low, close}\n// generated from musescript/indicators/lib/HeikinAshi.hx\n@strategy(\"ta.heikin_ashi\")\n@on(bar) {\n  var v = heikin_ashi();\n  plot(v.open, \"heikin_ashi.open\");\n  plot(v.high, \"heikin_ashi.high\");\n  plot(v.low, \"heikin_ashi.low\");\n  plot(v.close, \"heikin_ashi.close\");\n}\n", doc : "Heikin-Ashi: a smoothed synthetic candle series that filters out noise by averaging each bar with the running synthet...", file : "HeikinAshi.hx", argKinds : [], nativeSource : null},{ name : "heikin_ashi_oscillator", sig : "heikin_ashi_oscillator() -> Scalar", source : "// heikin_ashi_oscillator — Heikin-Ashi Oscillator: the synthetic Heikin-Ashi candle's own body size (see `HeikinAshi`), signed by direction — a ...\n// sig: heikin_ashi_oscillator() -> Scalar\n// generated from musescript/indicators/lib/HeikinAshiOscillator.hx\n@strategy(\"ta.heikin_ashi_oscillator\")\n@on(bar) {\n  var v = heikin_ashi_oscillator();\n  plot(v, \"heikin_ashi_oscillator\");\n}\n", doc : "Heikin-Ashi Oscillator: the synthetic Heikin-Ashi candle's own body size (see `HeikinAshi`), signed by direction — a ...", file : "HeikinAshiOscillator.hx", argKinds : [], nativeSource : null},{ name : "high_low_range", sig : "high_low_range() -> Scalar", source : "// high_low_range — High-Low Range: a stateless per-bar transform reporting the bar's raw trading range\n// sig: high_low_range() -> Scalar\n// generated from musescript/indicators/lib/HighLowRange.hx\n@strategy(\"ta.high_low_range\")\n@on(bar) {\n  var v = high_low_range();\n  plot(v, \"high_low_range\");\n}\n", doc : "High-Low Range: a stateless per-bar transform reporting the bar's raw trading range", file : "HighLowRange.hx", argKinds : [], nativeSource : null},{ name : "high_low_volume_nodes", sig : "high_low_volume_nodes(Window, Window) -> {hvn, lvn}", source : "// high_low_volume_nodes — High/Low Volume Nodes\n// sig: high_low_volume_nodes(Window, Window) -> {hvn, lvn}\n// generated from musescript/indicators/lib/HighLowVolumeNodes.hx\n@strategy(\"ta.high_low_volume_nodes\")\n@on(bar) {\n  var v = high_low_volume_nodes(5, 10);\n  plot(v.hvn, \"high_low_volume_nodes.hvn\");\n  plot(v.lvn, \"high_low_volume_nodes.lvn\");\n}\n", doc : "High/Low Volume Nodes", file : "HighLowVolumeNodes.hx", argKinds : ["TWindow","TWindow"], nativeSource : null},{ name : "high_wave", sig : "high_wave(Scalar) -> Scalar", source : "// high_wave — High Wave candlestick pattern — an extreme-indecision bar with a negligible body and long shadows on *both* sides (un...\n// sig: high_wave(Scalar) -> Scalar\n// generated from musescript/indicators/lib/HighWave.hx\n@strategy(\"ta.high_wave\")\n@on(bar) {\n  var v = high_wave(0.5);\n  plot(v, \"high_wave\");\n}\n", doc : "High Wave candlestick pattern — an extreme-indecision bar with a negligible body and long shadows on *both* sides (un...", file : "HighWave.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "highpass_filter", sig : "highpass_filter(Series, Window) -> Scalar", source : "// highpass_filter — Ehlers' 2-pole High-Pass Filter: isolates the cyclical/noise component of price by removing everything below a given ...\n// sig: highpass_filter(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/HighpassFilter.hx\n@strategy(\"ta.highpass_filter\")\n@on(bar) {\n  var v = highpass_filter(close, 5);\n  plot(v, \"highpass_filter\");\n}\n", doc : "Ehlers' 2-pole High-Pass Filter: isolates the cyclical/noise component of price by removing everything below a given ...", file : "HighpassFilter.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "hikkake", sig : "hikkake() -> Scalar", source : "// hikkake — Hikkake (\"trap\") pattern — a 3-bar setup: an inside bar (bar2 fully contained within bar1's range) followed by a bar3...\n// sig: hikkake() -> Scalar\n// generated from musescript/indicators/lib/Hikkake.hx\n@strategy(\"ta.hikkake\")\n@on(bar) {\n  var v = hikkake();\n  plot(v, \"hikkake\");\n}\n", doc : "Hikkake (\"trap\") pattern — a 3-bar setup: an inside bar (bar2 fully contained within bar1's range) followed by a bar3...", file : "Hikkake.hx", argKinds : [], nativeSource : null},{ name : "hikkake_modified", sig : "hikkake_modified() -> Scalar", source : "// hikkake_modified — Modified Hikkake — the same inside-bar trap as `Hikkake`, but requiring an extra confirmation bar: price must close b...\n// sig: hikkake_modified() -> Scalar\n// generated from musescript/indicators/lib/HikkakeModified.hx\n@strategy(\"ta.hikkake_modified\")\n@on(bar) {\n  var v = hikkake_modified();\n  plot(v, \"hikkake_modified\");\n}\n", doc : "Modified Hikkake — the same inside-bar trap as `Hikkake`, but requiring an extra confirmation bar: price must close b...", file : "HikkakeModified.hx", argKinds : [], nativeSource : null},{ name : "hilbert_dominant_cycle", sig : "hilbert_dominant_cycle(Series) -> Scalar", source : "// hilbert_dominant_cycle — Builtin wrapper exposing the `prim/HilbertDominantCycle` Ehlers dominant cycle estimator (already used internally by ...\n// sig: hilbert_dominant_cycle(Series) -> Scalar\n// generated from musescript/indicators/lib/HilbertDominantCycle.hx\n@strategy(\"ta.hilbert_dominant_cycle\")\n@on(bar) {\n  var v = hilbert_dominant_cycle(close);\n  plot(v, \"hilbert_dominant_cycle\");\n}\n", doc : "Builtin wrapper exposing the `prim/HilbertDominantCycle` Ehlers dominant cycle estimator (already used internally by ...", file : "HilbertDominantCycle.hx", argKinds : ["TSeries"], nativeSource : null},{ name : "hilo_activator", sig : "hilo_activator(Window) -> Scalar", source : "// hilo_activator — Hi-Lo Activator: a simple trend-following stop/reference line that switches between an SMA of highs (while short/down...\n// sig: hilo_activator(Window) -> Scalar\n// generated from musescript/indicators/lib/HiloActivator.hx\n@strategy(\"ta.hilo_activator\")\n@on(bar) {\n  var v = hilo_activator(5);\n  plot(v, \"hilo_activator\");\n}\n", doc : "Hi-Lo Activator: a simple trend-following stop/reference line that switches between an SMA of highs (while short/down...", file : "HiloActivator.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "historical_volatility", sig : "historical_volatility(Series, Window, Scalar) -> Scalar", source : "// historical_volatility — Historical (realized) Volatility: the annualized standard deviation of log returns over a trailing window of `period`...\n// sig: historical_volatility(Series, Window, Scalar) -> Scalar\n// generated from musescript/indicators/lib/HistoricalVolatility.hx\n@strategy(\"ta.historical_volatility\")\n@on(bar) {\n  var v = historical_volatility(close, 5, 0.5);\n  plot(v, \"historical_volatility\");\n}\n", doc : "Historical (realized) Volatility: the annualized standard deviation of log returns over a trailing window of `period`...", file : "HistoricalVolatility.hx", argKinds : ["TSeries","TWindow","TScalar"], nativeSource : null},{ name : "hma", sig : "hma(Series, Window) -> Scalar", source : "// hma — Hull Moving Average: Alan Hull's low-lag average, built by extrapolating a half-period WMA away from a full-period WM...\n// sig: hma(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/Hma.hx\n@strategy(\"ta.hma\")\n@on(bar) {\n  var v = hma(close, 5);\n  plot(v, \"hma\");\n}\n", doc : "Hull Moving Average: Alan Hull's low-lag average, built by extrapolating a half-period WMA away from a full-period WM...", file : "Hma.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "holt_winters", sig : "holt_winters(Series, Scalar, Scalar) -> Scalar", source : "// holt_winters — Holt's Linear (double exponential smoothing, \"Holt-Winters\" without the seasonal component, as commonly used in tradi...\n// sig: holt_winters(Series, Scalar, Scalar) -> Scalar\n// generated from musescript/indicators/lib/HoltWinters.hx\n@strategy(\"ta.holt_winters\")\n@on(bar) {\n  var v = holt_winters(close, 0.5, 0.5);\n  plot(v, \"holt_winters\");\n}\n", doc : "Holt's Linear (double exponential smoothing, \"Holt-Winters\" without the seasonal component, as commonly used in tradi...", file : "HoltWinters.hx", argKinds : ["TSeries","TScalar","TScalar"], nativeSource : null},{ name : "homing_pigeon", sig : "homing_pigeon() -> Scalar", source : "// homing_pigeon — Homing Pigeon candlestick pattern — a 2-bar bullish reversal: two consecutive red bars where the second's smaller bod...\n// sig: homing_pigeon() -> Scalar\n// generated from musescript/indicators/lib/HomingPigeon.hx\n@strategy(\"ta.homing_pigeon\")\n@on(bar) {\n  var v = homing_pigeon();\n  plot(v, \"homing_pigeon\");\n}\n", doc : "Homing Pigeon candlestick pattern — a 2-bar bullish reversal: two consecutive red bars where the second's smaller bod...", file : "HomingPigeon.hx", argKinds : [], nativeSource : null},{ name : "ht_dcphase", sig : "ht_dcphase(Series) -> Scalar", source : "// ht_dcphase — Ehlers' Hilbert Transform Dominant Cycle Phase (`HT_DCPHASE`)\n// sig: ht_dcphase(Series) -> Scalar\n// generated from musescript/indicators/lib/HtDcPhase.hx\n@strategy(\"ta.ht_dcphase\")\n@on(bar) {\n  var v = ht_dcphase(close);\n  plot(v, \"ht_dcphase\");\n}\n", doc : "Ehlers' Hilbert Transform Dominant Cycle Phase (`HT_DCPHASE`)", file : "HtDcPhase.hx", argKinds : ["TSeries"], nativeSource : null},{ name : "ht_phasor", sig : "ht_phasor(Series) -> {inphase, quadrature}", source : "// ht_phasor — Ehlers' Hilbert Transform Phasor (`HT_PHASOR`)\n// sig: ht_phasor(Series) -> {inphase, quadrature}\n// generated from musescript/indicators/lib/HtPhasor.hx\n@strategy(\"ta.ht_phasor\")\n@on(bar) {\n  var v = ht_phasor(close);\n  plot(v.inphase, \"ht_phasor.inphase\");\n  plot(v.quadrature, \"ht_phasor.quadrature\");\n}\n", doc : "Ehlers' Hilbert Transform Phasor (`HT_PHASOR`)", file : "HtPhasor.hx", argKinds : ["TSeries"], nativeSource : null},{ name : "ht_trendmode", sig : "ht_trendmode(Series) -> Scalar", source : "// ht_trendmode — Ehlers' Hilbert Transform Trend Mode (`HT_TRENDMODE`)\n// sig: ht_trendmode(Series) -> Scalar\n// generated from musescript/indicators/lib/HtTrendMode.hx\n@strategy(\"ta.ht_trendmode\")\n@on(bar) {\n  var v = ht_trendmode(close);\n  plot(v, \"ht_trendmode\");\n}\n", doc : "Ehlers' Hilbert Transform Trend Mode (`HT_TRENDMODE`)", file : "HtTrendMode.hx", argKinds : ["TSeries"], nativeSource : null},{ name : "hurst_channel", sig : "hurst_channel(Window) -> {upper, middle, lower}", source : "// hurst_channel — Hurst Channel: an ATR-band envelope whose width scales with the series' own `HurstExponent` estimate — the theoretica...\n// sig: hurst_channel(Window) -> {upper, middle, lower}\n// generated from musescript/indicators/lib/HurstChannel.hx\n@strategy(\"ta.hurst_channel\")\n@on(bar) {\n  var v = hurst_channel(5);\n  plot(v.upper, \"hurst_channel.upper\");\n  plot(v.middle, \"hurst_channel.middle\");\n  plot(v.lower, \"hurst_channel.lower\");\n}\n", doc : "Hurst Channel: an ATR-band envelope whose width scales with the series' own `HurstExponent` estimate — the theoretica...", file : "HurstChannel.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "hurst_exponent", sig : "hurst_exponent(Series, Window) -> Scalar", source : "// hurst_exponent — Hurst Exponent (single-scale rescaled-range estimator): estimates how mean-reverting (H < 0.5), random-walk-like (H ~...\n// sig: hurst_exponent(Series, Window) -> Scalar\n// generated from musescript/indicators/lib/HurstExponent.hx\n@strategy(\"ta.hurst_exponent\")\n@on(bar) {\n  var v = hurst_exponent(close, 5);\n  plot(v, \"hurst_exponent\");\n}\n", doc : "Hurst Exponent (single-scale rescaled-range estimator): estimates how mean-reverting (H < 0.5), random-walk-like (H ~...", file : "HurstExponent.hx", argKinds : ["TSeries","TWindow"], nativeSource : null},{ name : "ichimoku", sig : "ichimoku(Window, Window, Window) -> {tenkan, kijun, senkouA, senkouB, chikou}", source : "// ichimoku — Ichimoku Kinko Hyo: five lines built from rolling highest-high/lowest-low midpoints at three different lookback periods\n// sig: ichimoku(Window, Window, Window) -> {tenkan, kijun, senkouA, senkouB, chikou}\n// generated from musescript/indicators/lib/Ichimoku.hx\n@strategy(\"ta.ichimoku\")\n@on(bar) {\n  var v = ichimoku(5, 10, 15);\n  plot(v.tenkan, \"ichimoku.tenkan\");\n  plot(v.kijun, \"ichimoku.kijun\");\n  plot(v.senkouA, \"ichimoku.senkouA\");\n  plot(v.senkouB, \"ichimoku.senkouB\");\n  plot(v.chikou, \"ichimoku.chikou\");\n}\n", doc : "Ichimoku Kinko Hyo: five lines built from rolling highest-high/lowest-low midpoints at three different lookback periods", file : "Ichimoku.hx", argKinds : ["TWindow","TWindow","TWindow"], nativeSource : null},{ name : "identical_three_crows", sig : "identical_three_crows(Scalar) -> Scalar", source : "// identical_three_crows — Identical Three Crows candlestick pattern — a strong 3-bar bearish continuation: three consecutive long red bars, eac...\n// sig: identical_three_crows(Scalar) -> Scalar\n// generated from musescript/indicators/lib/IdenticalThreeCrows.hx\n@strategy(\"ta.identical_three_crows\")\n@on(bar) {\n  var v = identical_three_crows(0.5);\n  plot(v, \"identical_three_crows\");\n}\n", doc : "Identical Three Crows candlestick pattern — a strong 3-bar bearish continuation: three consecutive long red bars, eac...", file : "IdenticalThreeCrows.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "in_neck", sig : "in_neck(Scalar) -> Scalar", source : "// in_neck — In Neck candlestick pattern — a weak 2-bar bearish continuation: a long red bar followed by a green bar that gaps dow...\n// sig: in_neck(Scalar) -> Scalar\n// generated from musescript/indicators/lib/InNeck.hx\n@strategy(\"ta.in_neck\")\n@on(bar) {\n  var v = in_neck(0.5);\n  plot(v, \"in_neck\");\n}\n", doc : "In Neck candlestick pattern — a weak 2-bar bearish continuation: a long red bar followed by a green bar that gaps dow...", file : "InNeck.hx", argKinds : ["TScalar"], nativeSource : null},{ name : "inertia", sig : "inertia(Window, Window) -> Scalar", source : "// inertia — Inertia (Donald Dorsey): a linear-regression-smoothed Relative Vigor Index — RVI measures whether closes are settling...\n// sig: inertia(Window, Window) -> Scalar\n// generated from musescript/indicators/lib/Inertia.hx\n@strategy(\"ta.inertia\")\n@on(bar) {\n  var v = inertia(5, 10);\n  plot(v, \"inertia\");\n}\n", doc : "Inertia (Donald Dorsey): a linear-regression-smoothed Relative Vigor Index — RVI measures whether closes are settling...", file : "Inertia.hx", argKinds : ["TWindow","TWindow"], nativeSource : null},{ name : "information_ratio", sig : "information_ratio(Series, Series, Window) -> Scalar", source : "// information_ratio — Information Ratio: the mean excess return over a benchmark, divided by the tracking-error (stddev of that excess), ov...\n// sig: information_ratio(Series, Series, Window) -> Scalar\n// generated from musescript/indicators/lib/InformationRatio.hx\n@strategy(\"ta.information_ratio\")\n@on(bar) {\n  var v = information_ratio(close, close, 5);\n  plot(v, \"information_ratio\");\n}\n", doc : "Information Ratio: the mean excess return over a benchmark, divided by the tracking-error (stddev of that excess), ov...", file : "InformationRatio.hx", argKinds : ["TSeries","TSeries","TWindow"], nativeSource : null},{ name : "initial_balance", sig : "initial_balance(Window) -> {high, low}", source : "// initial_balance — Initial Balance: the high/low range established over the first `ibBars` bars of the series, held fixed for every bar ...\n// sig: initial_balance(Window) -> {high, low}\n// generated from musescript/indicators/lib/InitialBalance.hx\n@strategy(\"ta.initial_balance\")\n@on(bar) {\n  var v = initial_balance(5);\n  plot(v.high, \"initial_balance.high\");\n  plot(v.low, \"initial_balance.low\");\n}\n", doc : "Initial Balance: the high/low range established over the first `ibBars` bars of the series, held fixed for every bar ...", file : "InitialBalance.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "instantaneous_trendline", sig : "instantaneous_trendline(Series, Scalar) -> Scalar", source : "// instantaneous_trendline — Ehlers' Instantaneous Trendline: a near-zero-lag trendline built from a fixed-alpha recursive smoother tuned to track...\n// sig: instantaneous_trendline(Series, Scalar) -> Scalar\n// generated from musescript/indicators/lib/InstantaneousTrendline.hx\n@strategy(\"ta.instantaneous_trendline\")\n@on(bar) {\n  var v = instantaneous_trendline(close, 0.5);\n  plot(v, \"instantaneous_trendline\");\n}\n", doc : "Ehlers' Instantaneous Trendline: a near-zero-lag trendline built from a fixed-alpha recursive smoother tuned to track...", file : "InstantaneousTrendline.hx", argKinds : ["TSeries","TScalar"], nativeSource : null},{ name : "intraday_intensity", sig : "intraday_intensity(Window) -> Scalar", source : "// intraday_intensity — Intraday Intensity (Bostian): a volume-weighted measure of where the close settled within the bar's range, smoothed w...\n// sig: intraday_intensity(Window) -> Scalar\n// generated from musescript/indicators/lib/IntradayIntensity.hx\n@strategy(\"ta.intraday_intensity\")\n@on(bar) {\n  var v = intraday_intensity(5);\n  plot(v, \"intraday_intensity\");\n}\n", doc : "Intraday Intensity (Bostian): a volume-weighted measure of where the close settled within the bar's range, smoothed w...", file : "IntradayIntensity.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "intraday_momentum_index", sig : "intraday_momentum_index(Window) -> Scalar", source : "// intraday_momentum_index — Intraday Momentum Index: RSI's gain/loss ratio formula applied to each bar's *intraday* move (close vs\n// sig: intraday_momentum_index(Window) -> Scalar\n// generated from musescript/indicators/lib/IntradayMomentumIndex.hx\n@strategy(\"ta.intraday_momentum_index\")\n@on(bar) {\n  var v = intraday_momentum_index(5);\n  plot(v, \"intraday_momentum_index\");\n}\n", doc : "Intraday Momentum Index: RSI's gain/loss ratio formula applied to each bar's *intraday* move (close vs", file : "IntradayMomentumIndex.hx", argKinds : ["TWindow"], nativeSource : null},{ name : "intraday_volatility_profile", sig : "intraday_volatility_profile(Window, Scalar) -> {bins}", source : "// intraday_volatility_profile — Intraday Volatility Profile\n// sig: intraday_volatility_profile(Window, Scalar) -> {bins}\n// generated from musescript/indicators/lib/IntradayVolatilityProfile.hx\n@strategy(\"ta.intraday_volatility_profile\")\n@on(bar) {\n  var v = intraday_volatility_profile(5, 0.5);\n  plot(v.bins, \"intraday_volatility_profile.bins\");\n}\n", doc : "Intraday Volatility Profile", file : "IntradayVolatilityProfile.hx", argKinds : ["TWindow","TScalar"],